1	import { Router } from 'express';
2	import * as authController from '../controllers/auth.controller';
3	import { authenticate } from '../middleware/auth';
4	import { validate } from '../middleware/validate';
5	import {
6	  registerSchema,
7	  loginSchema,
8	  refreshTokenSchema,
9	  updateProfileSchema,
10	} from '../lib/validation-schemas';
11	
12	const router = Router();
13	
14	router.post('/register', validate(registerSchema), authController.register);
15	router.post('/login', validate(loginSchema), authController.login);
16	router.post('/refresh', validate(refreshTokenSchema), authController.refreshToken);
