5	export async function register(req: Request, res: Response, next: NextFunction) {
6	  try {
7	    const result = await authService.register(req.body);
8	    await logAuditEvent({
9	      userId: result.user._id?.toString() || '',
10	      role: result.user.role || 'buyer',
11	      ip: req.ip || '',
12	      action: 'user.register',
13	      resourceType: 'user',
14	      resourceId: result.user._id?.toString() || '',
15	      after: { email: result.user.email, role: result.user.role },
16	      requestId: (req as any).requestId,
17	    });
18	    res.status(201).json(result);
19	  } catch (error) {
20	    next(error);
21	  }
22	}
