24	export async function login(req: Request, res: Response, next: NextFunction) {
25	  try {
26	    const { email, password } = req.body;
27	    const result = await authService.login(email, password);
28	    await logAuditEvent({
29	      userId: result.user._id?.toString() || '',
30	      role: result.user.role || '',
31	      ip: req.ip || '',
32	      action: 'user.login',
33	      resourceType: 'user',
34	      resourceId: result.user._id?.toString() || '',
35	      requestId: (req as any).requestId,
36	    });
37	    res.json(result);
38	  } catch (error) {
39	    next(error);
