80	export async function updateProfile(req: Request, res: Response, next: NextFunction) {
81	  try {
82	    const before = await authService.getProfile(req.user!.id);
83	    const user = await authService.updateProfile(req.user!.id, req.body);
84	    await logAuditEvent({
85	      userId: req.user!.id,
86	      role: req.user!.role,
87	      ip: req.ip || '',
88	      action: 'user.update_profile',
89	      resourceType: 'user',
