1	import jwt from 'jsonwebtoken';
2	import { User, IUser } from '../models/user.model';
3	import { Dealership } from '../models/dealership.model';
4	import config from '../config';
5	import { BadRequestError, UnauthorizedError, NotFoundError, ConflictError } from '../lib/errors';
6	import logger from '../lib/logger';
7	import { encryptValue, decryptValue } from './privacy/encryption.service';
8	import { EncryptedData } from '../lib/crypto';
9	
10	interface RegisterInput {
11	  email: string;
12	  password: string;
13	  firstName: string;
14	  lastName: string;
15	  role?: string;
16	  dealershipId?: string;
17	}
18	
19	interface TokenPair {
20	  accessToken: string;
21	  refreshToken: string;
22	}
23	
24	function generateTokens(user: IUser): TokenPair {
25	  const payload = {
26	    id: user._id.toString(),
27	    email: user.email,
28	    role: user.role,
29	    dealershipId: user.dealershipId?.toString() || null,
30	  };
31	
32	  const accessToken = jwt.sign(payload, config.jwtSecret, {
33	    expiresIn: 3600,
34	  });
35	
36	  const refreshToken = jwt.sign(payload, config.jwtRefreshSecret, {
37	    expiresIn: 604800,
38	  });
39	
40	  return { accessToken, refreshToken };
41	}
42	
43	async function encryptSensitiveFields(user: IUser) {
44	  if (user.profile.driversLicense && !user.profile.driversLicenseEncrypted) {
45	    user.profile.driversLicenseEncrypted = await encryptValue(user.profile.driversLicense);
46	    user.profile.driversLicense = user.profile.driversLicense.slice(-4).padStart(user.profile.driversLicense.length, '*');
47	  }
48	  if (user.profile.ssn && !user.profile.ssnEncrypted) {
49	    user.profile.ssnEncrypted = await encryptValue(user.profile.ssn);
50	    user.profile.ssn = user.profile.ssn.slice(-4).padStart(user.profile.ssn.length, '*');
51	  }
52	}
53	
54	async function decryptSensitiveFields(userJson: any): Promise<any> {
55	  if (userJson.profile?.driversLicenseEncrypted) {
56	    try {
57	      userJson.profile.driversLicense = await decryptValue(userJson.profile.driversLicenseEncrypted as EncryptedData);
58	    } catch { /* masked value remains */ }
59	  }
60	  if (userJson.profile?.ssnEncrypted) {
61	    try {
62	      userJson.profile.ssn = await decryptValue(userJson.profile.ssnEncrypted as EncryptedData);
63	    } catch { /* masked value remains */ }
64	  }
65	  return userJson;
66	}
67	
68	export async function register(input: RegisterInput) {
69	  // Public registration always creates buyer — role escalation only via admin endpoint
70	  const existing = await User.findOne({
71	    email: input.email,
72	    dealershipId: null,
73	  });
74	  if (existing) {
75	    throw new ConflictError('Email already registered');
76	  }
77	
78	  const user = new User({
79	    email: input.email,
80	    passwordHash: input.password,
81	    role: 'buyer',
82	    dealershipId: null,
83	    profile: {
84	      firstName: input.firstName,
85	      lastName: input.lastName,
86	    },
87	  });
88	
89	  await user.save();
90	
91	  const tokens = generateTokens(user);
92	  user.refreshToken = tokens.refreshToken;
93	  await user.save();
94	
95	  logger.info({ userId: user._id, email: user.email }, 'User registered');
96	
97	  return { user: user.toJSON(), ...tokens };
98	}
99	
100	export async function login(email: string, password: string) {
101	  const user = await User.findOne({ email, isActive: true });
102	  if (!user) {
103	    throw new UnauthorizedError('Invalid email or password');
104	  }
105	
106	  const isValid = await user.comparePassword(password);
107	  if (!isValid) {
108	    throw new UnauthorizedError('Invalid email or password');
109	  }
110	
111	  const tokens = generateTokens(user);
112	  user.refreshToken = tokens.refreshToken;
113	  await user.save();
114	
115	  logger.info({ userId: user._id, email: user.email }, 'User logged in');
116	
117	  return { user: user.toJSON(), ...tokens };
118	}
119	
120	export async function refreshTokens(refreshToken: string) {
121	  try {
122	    const decoded = jwt.verify(refreshToken, config.jwtRefreshSecret) as any;
123	    const user = await User.findById(decoded.id);
124	
125	    if (!user || user.refreshToken !== refreshToken || !user.isActive) {
126	      throw new UnauthorizedError('Invalid refresh token');
127	    }
128	
129	    const tokens = generateTokens(user);
130	    user.refreshToken = tokens.refreshToken;
131	    await user.save();
132	
133	    return tokens;
134	  } catch {
135	    throw new UnauthorizedError('Invalid refresh token');
136	  }
137	}
138	
139	export async function logout(userId: string) {
140	  await User.findByIdAndUpdate(userId, { refreshToken: null });
141	  logger.info({ userId }, 'User logged out');
142	}
143	
144	export async function getProfile(userId: string) {
145	  const user = await User.findById(userId).populate('dealershipId');
146	  if (!user) {
147	    throw new NotFoundError('User not found');
148	  }
149	  const json = user.toJSON();
150	  return decryptSensitiveFields(json);
151	}
152	
153	export async function updateProfile(
154	  userId: string,
155	  updates: Partial<{ firstName: string; lastName: string; phone: string; driversLicense: string; ssn: string }>
156	) {
157	  const user = await User.findById(userId);
158	  if (!user) {
159	    throw new NotFoundError('User not found');
160	  }
161	
162	  if (updates.firstName) user.profile.firstName = updates.firstName;
163	  if (updates.lastName) user.profile.lastName = updates.lastName;
164	  if (updates.phone) user.profile.phone = updates.phone;
165	  if (updates.driversLicense) {
166	    user.profile.driversLicense = updates.driversLicense;
167	    user.profile.driversLicenseEncrypted = null as any;
168	  }
169	  if (updates.ssn) {
170	    user.profile.ssn = updates.ssn;
171	    user.profile.ssnEncrypted = null as any;
172	  }
173	
174	  await encryptSensitiveFields(user);
175	  await user.save();
176	  const json = user.toJSON();
177	  return decryptSensitiveFields(json);
178	}
