1	import mongoose, { Schema, Document } from 'mongoose';
2	import bcrypt from 'bcryptjs';
3	import { Role } from '../types/enums';
4	
5	export interface IUser extends Document {
6	  email: string;
7	  passwordHash: string;
8	  role: Role;
9	  dealershipId: mongoose.Types.ObjectId | null;
10	  profile: {
11	    firstName: string;
12	    lastName: string;
13	    phone: string;
14	    driversLicense?: string;
15	    driversLicenseEncrypted?: Record<string, any> | null;
16	    ssn?: string;
17	    ssnEncrypted?: Record<string, any> | null;
18	  };
19	  isActive: boolean;
20	  deletedAt: Date | null;
21	  pendingPurge: boolean;
22	  consentVersion: string;
23	  refreshToken?: string;
24	  createdAt: Date;
25	  updatedAt: Date;
26	  comparePassword(password: string): Promise<boolean>;
27	}
28	
29	const userSchema = new Schema<IUser>(
30	  {
31	    email: { type: String, required: true, lowercase: true, trim: true },
32	    passwordHash: { type: String, required: true },
33	    role: {
34	      type: String,
35	      enum: Object.values(Role),
36	      default: Role.BUYER,
37	    },
38	    dealershipId: { type: Schema.Types.ObjectId, ref: 'Dealership', default: null },
39	    profile: {
40	      firstName: { type: String, required: true },
41	      lastName: { type: String, required: true },
42	      phone: { type: String, default: '' },
43	      driversLicense: { type: String, default: '' },
44	      driversLicenseEncrypted: { type: Schema.Types.Mixed, default: null },
45	      ssn: { type: String, default: '' },
46	      ssnEncrypted: { type: Schema.Types.Mixed, default: null },
47	    },
48	    isActive: { type: Boolean, default: true },
49	    deletedAt: { type: Date, default: null },
50	    pendingPurge: { type: Boolean, default: false },
51	    consentVersion: { type: String, default: '1.0' },
52	    refreshToken: { type: String },
53	  },
54	  { timestamps: true }
55	);
56	
57	userSchema.index({ email: 1, dealershipId: 1 }, { unique: true });
58	userSchema.index({ dealershipId: 1, role: 1 });
59	
60	userSchema.pre('save', async function (next) {
61	  if (this.isModified('passwordHash') && !this.passwordHash.startsWith('$2')) {
62	    this.passwordHash = await bcrypt.hash(this.passwordHash, 12);
63	  }
64	  next();
65	});
66	
67	userSchema.methods.comparePassword = async function (password: string): Promise<boolean> {
68	  return bcrypt.compare(password, this.passwordHash);
69	};
70	
71	userSchema.set('toJSON', {
72	  transform(_doc: any, ret: any) {
73	    delete ret.passwordHash;
74	    delete ret.refreshToken;
75	    delete ret.__v;
76	    return ret;
77	  },
78	});
79	
80	export const User = mongoose.model<IUser>('User', userSchema);

