1	import { Request, Response, NextFunction } from 'express';
2	import { Role } from '../types/enums';
3	import { ForbiddenError, UnauthorizedError } from '../lib/errors';
4	
5	export function requireRole(...roles: Role[]) {
6	  return (req: Request, _res: Response, next: NextFunction): void => {
7	    if (!req.user) {
8	      next(new UnauthorizedError('Authentication required'));
9	      return;
10	    }
11	
