3	const ALGORITHM = 'aes-256-gcm';
4	const IV_LENGTH = 16;
5	const TAG_LENGTH = 16;
6	
7	export interface EncryptedData {
8	  ciphertext: string;
9	  iv: string;
10	  tag: string;
11	  keyVersion: string;
12	}
13	
14	export function encrypt(plaintext: string, key: Buffer, keyVersion: string): EncryptedData {
15	  const iv = crypto.randomBytes(IV_LENGTH);
16	  const cipher = crypto.createCipheriv(ALGORITHM, key, iv);
17	  let ciphertext = cipher.update(plaintext, 'utf8', 'hex');
18	  ciphertext += cipher.final('hex');
19	  const tag = cipher.getAuthTag();
20	
21	  return {
22	    ciphertext,
23	    iv: iv.toString('hex'),
24	    tag: tag.toString('hex'),
25	    keyVersion,
26	  };
27	}
28	
29	export function decrypt(data: EncryptedData, key: Buffer): string {
30	  const decipher = crypto.createDecipheriv(
31	    ALGORITHM,
32	    key,
33	    Buffer.from(data.iv, 'hex')
34	  );
35	  decipher.setAuthTag(Buffer.from(data.tag, 'hex'));
36	  let plaintext = decipher.update(data.ciphertext, 'hex', 'utf8');
37	  plaintext += decipher.final('utf8');
38	  return plaintext;
39	}
