80	function resolveAccountId(req: Request): string {
81	  const role = req.user!.role;
82	  // Admins can query specific accounts via X-Dealership-Id header scope
83	  if (role === 'admin' && req.scope?.dealershipId) {
84	    return `dealership:${req.scope.dealershipId}`;
85	  }
86	  if (role === 'buyer') return `buyer:${req.user!.id}`;
87	  const dealershipId = req.user!.dealershipId || req.scope?.dealershipId;
88	  if (dealershipId && (role === 'dealership_staff' || role === 'finance_reviewer')) {
89	    return `dealership:${dealershipId}`;
90	  }
91	  return `user:${req.user!.id}`;
92	}
