43	async function encryptSensitiveFields(user: IUser) {
44	  if (user.profile.driversLicense && !user.profile.driversLicenseEncrypted) {
45	    user.profile.driversLicenseEncrypted = await encryptValue(user.profile.driversLicense);
46	    user.profile.driversLicense = user.profile.driversLicense.slice(-4).padStart(user.profile.driversLicense.length, '*');
47	  }
48	  if (user.profile.ssn && !user.profile.ssnEncrypted) {
49	    user.profile.ssnEncrypted = await encryptValue(user.profile.ssn);
50	    user.profile.ssn = user.profile.ssn.slice(-4).padStart(user.profile.ssn.length, '*');
51	  }
52	}
53	
54	async function decryptSensitiveFields(userJson: any): Promise<any> {
55	  if (userJson.profile?.driversLicenseEncrypted) {
56	    try {
57	      userJson.profile.driversLicense = await decryptValue(userJson.profile.driversLicenseEncrypted as EncryptedData);
58	    } catch { /* masked value remains */ }
59	  }
60	  if (userJson.profile?.ssnEncrypted) {
61	    try {
62	      userJson.profile.ssn = await decryptValue(userJson.profile.ssnEncrypted as EncryptedData);
63	    } catch { /* masked value remains */ }
64	  }
65	  return userJson;
66	}
