120	export async function refreshTokens(refreshToken: string) {
121	  try {
122	    const decoded = jwt.verify(refreshToken, config.jwtRefreshSecret) as any;
123	    const user = await User.findById(decoded.id);
124	
125	    if (!user || user.refreshToken !== refreshToken || !user.isActive) {
126	      throw new UnauthorizedError('Invalid refresh token');
127	    }
128	
129	    const tokens = generateTokens(user);
130	    user.refreshToken = tokens.refreshToken;
131	    await user.save();
132	
133	    return tokens;
134	  } catch {
135	    throw new UnauthorizedError('Invalid refresh token');
136	  }
137	}
