2	import { Invoice } from '../../models/invoice.model';
3	import { Order } from '../../models/order.model';
4	import { PaymentMethod, PaymentStatus, InvoiceStatus } from '../../types/enums';
5	import { NotFoundError, BadRequestError } from '../../lib/errors';
6	import { recordTransaction } from './wallet-ledger.service';
7	import { resolveAdapter } from './payment-adapter';
8	import logger from '../../lib/logger';
9	
10	interface PaymentInput {
11	  orderId: string;
12	  invoiceId: string;
13	  dealershipId: string;
14	  method: string;
15	  amount: number;
16	  idempotencyKey: string;
17	  metadata?: Record<string, any>;
18	}
19	
20	export async function processPayment(input: PaymentInput) {
21	  // Validate payment method before any DB operations
22	  const adapter = resolveAdapter(input.method);
23	
24	  const existing = await Payment.findOne({ idempotencyKey: input.idempotencyKey });
25	  if (existing) return existing;
26	
27	  const invoice = await Invoice.findById(input.invoiceId);
28	  if (!invoice) throw new NotFoundError('Invoice not found');
29	  if (invoice.status === InvoiceStatus.PAID) {
30	    throw new BadRequestError('Invoice already paid');
31	  }
32	
33	  if (input.amount !== invoice.total) {
34	    throw new BadRequestError(
35	      `Payment amount (${input.amount}) does not match invoice total (${invoice.total})`
36	    );
37	  }
38	
39	  const order = await Order.findById(input.orderId);
40	  if (!order) throw new NotFoundError('Order not found');
41	
42	  const adapterResult = await adapter.charge({
43	    amount: input.amount,
44	    currency: 'USD',
45	    orderId: input.orderId,
46	    invoiceId: input.invoiceId,
47	    method: input.method,
48	    metadata: input.metadata,
49	  });
50	
51	  if (!adapterResult.success) {
52	    const failedPayment = new Payment({
53	      dealershipId: input.dealershipId,
54	      orderId: input.orderId,
55	      invoiceId: input.invoiceId,
56	      method: input.method as PaymentMethod,
57	      amount: input.amount,
58	      status: PaymentStatus.FAILED,
59	      adapterUsed: adapter.name,
60	      metadata: { ...input.metadata, adapterResult },
61	      idempotencyKey: input.idempotencyKey,
62	    });
63	    await failedPayment.save();
64	    throw new BadRequestError('Payment processing failed');
65	  }
66	
67	  const payment = new Payment({
68	    dealershipId: input.dealershipId,
69	    orderId: input.orderId,
70	    invoiceId: input.invoiceId,
71	    method: input.method as PaymentMethod,
72	    amount: input.amount,
73	    status: PaymentStatus.COMPLETED,
74	    adapterUsed: adapter.name,
75	    metadata: { ...input.metadata, adapterTransactionId: adapterResult.transactionId, ...adapterResult.metadata },
76	    idempotencyKey: input.idempotencyKey,
77	  });
78	
79	  await payment.save();
80	
81	  await recordTransaction({
82	    dealershipId: input.dealershipId,
83	    debitAccountId: `buyer:${order.buyerId}`,
84	    creditAccountId: `dealership:${input.dealershipId}`,
85	    amount: input.amount,
86	    referenceType: 'payment',
87	    referenceId: payment._id.toString(),
88	    description: `Payment for order ${order.orderNumber}`,
89	    idempotencyKey: `payment-${payment._id}`,
90	  });
91	
92	  invoice.status = InvoiceStatus.PAID;
93	  await invoice.save();
94	
95	  logger.info(
96	    { paymentId: payment._id, orderId: input.orderId, amount: input.amount, method: input.method, adapter: adapter.name },
97	    'Payment processed'
98	  );
99	
100	  return payment;
101	}
