5	export interface PaymentAdapterResult {
6	  success: boolean;
7	  transactionId: string;
8	  status: 'completed' | 'pending' | 'failed';
9	  metadata: Record<string, any>;
10	}
11	
12	export interface PaymentAdapter {
13	  name: string;
14	  supports(method: string): boolean;
15	  charge(params: {
16	    amount: number;
17	    currency: string;
18	    orderId: string;
19	    invoiceId: string;
20	    method: string;
21	    metadata?: Record<string, any>;
22	  }): Promise<PaymentAdapterResult>;
23	  refund(transactionId: string, amount: number): Promise<PaymentAdapterResult>;
24	}
25	
26	export class OfflinePaymentAdapter implements PaymentAdapter {
27	  name = 'offline';
28	
29	  supports(method: string): boolean {
30	    return ['cash', 'cashier_check', 'in_house_financing'].includes(method);
31	  }
32	
33	  async charge(params: {
34	    amount: number;
35	    currency: string;
36	    orderId: string;
37	    invoiceId: string;
38	    method: string;
39	    metadata?: Record<string, any>;
40	  }): Promise<PaymentAdapterResult> {
41	    logger.info({ adapter: this.name, method: params.method, amount: params.amount }, 'Offline payment recorded');
42	    return {
43	      success: true,
44	      transactionId: `offline-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`,
45	      status: 'completed',
46	      metadata: { method: params.method, recordedAt: new Date().toISOString() },
47	    };
48	  }
49	
50	  async refund(transactionId: string, amount: number): Promise<PaymentAdapterResult> {
51	    logger.info({ adapter: this.name, transactionId, amount }, 'Offline refund recorded');
52	    return {
53	      success: true,
54	      transactionId: `offline-refund-${Date.now()}`,
55	      status: 'completed',
56	      metadata: { originalTransactionId: transactionId, refundedAt: new Date().toISOString() },
57	    };
58	  }
59	}
60	
61	export class OnlinePaymentAdapter implements PaymentAdapter {
62	  name = 'online';
63	
64	  supports(method: string): boolean {
65	    return ['credit_card', 'bank_transfer'].includes(method);
66	  }
67	
68	  async charge(params: {
69	    amount: number;
70	    currency: string;
71	    orderId: string;
72	    invoiceId: string;
73	    method: string;
74	    metadata?: Record<string, any>;
75	  }): Promise<PaymentAdapterResult> {
76	    // In production, this would call an external payment gateway (Stripe, etc.)
77	    // For now, simulate a successful online charge
78	    logger.info({ adapter: this.name, method: params.method, amount: params.amount }, 'Online payment processed');
79	    return {
80	      success: true,
81	      transactionId: `online-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`,
82	      status: 'completed',
83	      metadata: {
84	        method: params.method,
85	        gateway: 'simulated',
86	        processedAt: new Date().toISOString(),
87	      },
88	    };
89	  }
90	
91	  async refund(transactionId: string, amount: number): Promise<PaymentAdapterResult> {
92	    logger.info({ adapter: this.name, transactionId, amount }, 'Online refund processed');
93	    return {
94	      success: true,
95	      transactionId: `online-refund-${Date.now()}`,
96	      status: 'completed',
97	      metadata: { originalTransactionId: transactionId, refundedAt: new Date().toISOString() },
98	    };
99	  }
100	}
101	
102	const adapters: PaymentAdapter[] = [
103	  new OfflinePaymentAdapter(),
104	  new OnlinePaymentAdapter(),
105	];
106	
107	const ONLINE_METHODS = ['credit_card', 'bank_transfer'];
108	
109	export function resolveAdapter(method: string): PaymentAdapter {
110	  if (ONLINE_METHODS.includes(method) && !config.enableOnlinePayments) {
111	    throw new BadRequestError(`Online payment method "${method}" is not enabled. Only offline methods are accepted.`);
112	  }
113	  const adapter = adapters.find((a) => a.supports(method));
114	  if (!adapter) {
115	    throw new BadRequestError(`No payment adapter found for method: ${method}`);
116	  }
117	  return adapter;
118	}
119	
120	export function registerAdapter(adapter: PaymentAdapter) {
121	  adapters.push(adapter);
122	}
