1	import { PermissionOverride } from '../models/permission-override.model';
2	import { DocumentModel } from '../models/document.model';
3	import { Role, PermissionEffect } from '../types/enums';
4	
5	const DEFAULT_PERMISSIONS: Record<string, Record<string, string[]>> = {
6	  document: {
7	    [Role.ADMIN]: ['read', 'write', 'delete', 'download', 'share', 'submit', 'approve'],
8	    [Role.DEALERSHIP_STAFF]: ['read', 'write', 'delete', 'download', 'share', 'submit'],
9	    [Role.FINANCE_REVIEWER]: ['read', 'download', 'submit', 'approve'],
10	    [Role.BUYER]: ['read', 'download'],
11	  },
12	  order: {
13	    [Role.ADMIN]: ['read', 'write', 'delete'],
14	    [Role.DEALERSHIP_STAFF]: ['read', 'write'],
15	    [Role.FINANCE_REVIEWER]: ['read'],
16	    [Role.BUYER]: ['read'],
17	  },
18	};
19	
20	export async function checkPermission(
21	  userId: string,
22	  role: string,
23	  dealershipId: string,
24	  resource: string,
25	  resourceId: string | null,
26	  action: string,
27	  sensitiveFlag: boolean = false
28	): Promise<boolean> {
29	  if (role === Role.ADMIN) return true;
30	
31	  if (sensitiveFlag && role !== Role.FINANCE_REVIEWER && role !== Role.ADMIN) {
32	    const override = await PermissionOverride.findOne({
33	      dealershipId,
34	      resource,
35	      resourceId,
36	      userId,
37	      actions: action,
38	      effect: PermissionEffect.ALLOW,
39	      $or: [{ expiresAt: null }, { expiresAt: { $gt: new Date() } }],
40	    });
41	    if (override) return true;
42	
43	    // Also check document-level overrides for document resources
44	    if (resource === 'document' && resourceId) {
45	      const hasDocOverride = await checkDocumentLevelOverride(resourceId, userId, action);
46	      if (hasDocOverride) return true;
47	    }
48	
49	    return false;
50	  }
51	
52	  // Check PermissionOverride model (admin-managed overrides)
53	  if (resourceId) {
54	    const userOverride = await PermissionOverride.findOne({
55	      dealershipId,
56	      resource,
57	      resourceId,
58	      userId,
59	      actions: action,
60	      $or: [{ expiresAt: null }, { expiresAt: { $gt: new Date() } }],
61	    });
62	    if (userOverride) return userOverride.effect === PermissionEffect.ALLOW;
63	
64	    const roleOverride = await PermissionOverride.findOne({
65	      dealershipId,
66	      resource,
67	      resourceId,
68	      role,
69	      userId: null,
70	      actions: action,
71	      $or: [{ expiresAt: null }, { expiresAt: { $gt: new Date() } }],
72	    });
73	    if (roleOverride) return roleOverride.effect === PermissionEffect.ALLOW;
74	  }
75	
76	  // Check document-level overrides (from share workflow)
77	  if (resource === 'document' && resourceId) {
78	    const hasDocOverride = await checkDocumentLevelOverride(resourceId, userId, action);
79	    if (hasDocOverride) return true;
80	  }
81	
82	  const userDealershipOverride = await PermissionOverride.findOne({
83	    dealershipId,
84	    resource,
85	    resourceId: null,
86	    userId,
87	    actions: action,
88	    $or: [{ expiresAt: null }, { expiresAt: { $gt: new Date() } }],
89	  });
90	  if (userDealershipOverride) return userDealershipOverride.effect === PermissionEffect.ALLOW;
91	
92	  const roleDealershipOverride = await PermissionOverride.findOne({
93	    dealershipId,
94	    resource,
95	    resourceId: null,
96	    role,
97	    userId: null,
98	    actions: action,
99	    $or: [{ expiresAt: null }, { expiresAt: { $gt: new Date() } }],
100	  });
101	  if (roleDealershipOverride) return roleDealershipOverride.effect === PermissionEffect.ALLOW;
102	
103	  const resourceDefaults = DEFAULT_PERMISSIONS[resource];
104	  if (!resourceDefaults) return false;
105	  const roleDefaults = resourceDefaults[role];
106	  if (!roleDefaults) return false;
107	  return roleDefaults.includes(action);
108	}
109	
110	async function checkDocumentLevelOverride(
111	  documentId: string,
112	  userId: string,
113	  action: string
114	): Promise<boolean> {
115	  const doc = await DocumentModel.findById(documentId).select('permissions');
116	  if (!doc) return false;
117	
118	  const override = doc.permissions.overrides.find(
119	    (o) => o.userId.toString() === userId && o.actions.includes(action)
120	  );
121	  return !!override;
122	}
