35	export async function getAuditLogs(
36	  filters: {
37	    dealershipId?: string;
38	    userId?: string;
39	    resourceType?: string;
40	    resourceId?: string;
41	    action?: string;
42	  },
43	  pagination: PaginationParams
44	) {
45	  const query: any = {};
46	  if (filters.dealershipId) query.dealershipId = filters.dealershipId;
47	  if (filters.userId) query['actor.userId'] = filters.userId;
48	  if (filters.resourceType) query['resource.type'] = filters.resourceType;
