50	  if (filters.action) query.action = new RegExp(filters.action, 'i');
51	
52	  const sort: any = { timestamp: -1 };
53	  const skip = (pagination.page - 1) * pagination.limit;
54	
55	  const [data, total] = await Promise.all([
56	    AuditLog.find(query).sort(sort).skip(skip).limit(pagination.limit),
57	    AuditLog.countDocuments(query),
58	  ]);
59	
60	  return buildPaginatedResult(data, total, pagination);
61	}
