3	const SENSITIVE_PATTERNS = [
4	  'ssn', 'driversLicense', 'driversLicenseEncrypted', 'ssnEncrypted',
5	  'password', 'passwordHash', 'refreshToken', 'accessToken',
6	  'creditCard', 'cardNumber',
7	];
8	
9	const logger = pino({
10	  level: process.env.LOG_LEVEL || 'info',
11	  transport:
12	    process.env.NODE_ENV === 'development'
13	      ? { target: 'pino-pretty', options: { colorize: true } }
14	      : undefined,
15	  redact: {
16	    paths: SENSITIVE_PATTERNS.flatMap((field) => [
17	      field,
18	      `*.${field}`,
19	      `*.*.${field}`,
20	      `*.profile.${field}`,
21	    ]),
22	    censor: '[REDACTED]',
23	  },
24	  formatters: {
25	    level(label) {
26	      return { level: label };
27	    },
28	  },
29	  timestamp: pino.stdTimeFunctions.isoTime,
30	});
31	
32	export default logger;
33	
34	export function sanitizeForAudit(data: Record<string, any> | null | undefined): Record<string, any> | null {
35	  if (!data) return null;
36	  const sanitized = { ...data };
37	  for (const key of Object.keys(sanitized)) {
38	    if (SENSITIVE_PATTERNS.some((p) => key.toLowerCase().includes(p.toLowerCase()))) {
39	      sanitized[key] = '[REDACTED]';
40	    }
41	    if (sanitized[key] && typeof sanitized[key] === 'object' && !Array.isArray(sanitized[key])) {
42	      sanitized[key] = sanitizeForAudit(sanitized[key]);
43	    }
44	  }
45	  return sanitized;
46	}
