332	export async function listOrders(
333	  filters: { dealershipId?: string; buyerId?: string; status?: string },
334	  pagination: PaginationParams
335	) {
336	  const query: any = {};
337	  if (filters.dealershipId) query.dealershipId = filters.dealershipId;
338	  if (filters.buyerId) query.buyerId = filters.buyerId;
339	  if (filters.status) query.status = filters.status;
340	
341	  const sort: any = { [pagination.sortBy]: pagination.sortOrder === 'asc' ? 1 : -1 };
342	  const skip = (pagination.page - 1) * pagination.limit;
343	
344	  const [data, total] = await Promise.all([
345	    Order.find(query)
346	      .sort(sort)
347	      .skip(skip)
348	      .limit(pagination.limit)
349	      .populate('buyerId', 'email profile'),
350	    Order.countDocuments(query),
351	  ]);
352	
353	  return buildPaginatedResult(data, total, pagination);
354	}
