360	export async function mergeOrders(orderIds: string[], userId: string) {
361	  if (orderIds.length < 2) {
362	    throw new BadRequestError('At least two orders are required for merge');
363	  }
364	
365	  const orders = await Order.find({ _id: { $in: orderIds } });
366	  if (orders.length !== orderIds.length) {
367	    throw new NotFoundError('One or more orders not found');
368	  }
369	
370	  const dealershipIds = new Set(orders.map((o) => o.dealershipId.toString()));
371	  if (dealershipIds.size > 1) {
372	    throw new BadRequestError('Cannot merge orders from different dealerships');
373	  }
374	
375	  const buyerIds = new Set(orders.map((o) => o.buyerId.toString()));
376	  if (buyerIds.size > 1) {
377	    throw new BadRequestError('Cannot merge orders from different buyers');
378	  }
379	
380	  for (const order of orders) {
381	    if (order.status !== OrderStatus.CREATED && order.status !== OrderStatus.RESERVED) {
382	      throw new BadRequestError(
383	        `Order ${order.orderNumber} is in "${order.status}" status and cannot be merged`
384	      );
385	    }
386	  }
387	
388	  const session = await mongoose.startSession();
389	
390	  try {
391	    let merged: IOrder | null = null;
392	
393	    await session.withTransaction(async () => {
394	      const primary = orders[0];
395	      const others = orders.slice(1);
396	
397	      const allItems = orders.flatMap((o) => o.items);
398	      const subtotal = allItems.reduce((sum, item) => sum + item.subtotal, 0);
399	
400	      primary.items = allItems as any;
401	      primary.totals = { subtotal, tax: 0, total: subtotal };
402	      primary.childOrderIds = [];
403	      primary.parentOrderId = null as any;
404	      await primary.save({ session });
405	
406	      for (const other of others) {
407	        await OrderEventModel.create(
408	          [
409	            {
410	              orderId: other._id,
411	              fromStatus: other.status,
412	              toStatus: OrderStatus.CANCELLED,
413	              triggeredBy: userId,
414	              reason: `Merged into order ${primary.orderNumber}`,
415	            },
416	          ],
417	          { session }
418	        );
419	        other.status = OrderStatus.CANCELLED;
420	        other.cancelledAt = new Date();
421	        other.cancelReason = `Merged into order ${primary.orderNumber}`;
422	        other.parentOrderId = null as any;
423	        other.childOrderIds = [];
424	        await other.save({ session });
425	      }
426	
427	      await OrderEventModel.create(
428	        [
429	          {
430	            orderId: primary._id,
431	            fromStatus: primary.status,
432	            toStatus: primary.status,
433	            triggeredBy: userId,
434	            reason: `Merged orders: ${others.map((o) => o.orderNumber).join(', ')}`,
435	          },
436	        ],
437	        { session }
438	      );
439	
440	      merged = primary;
441	    });
442	
443	    logger.info(
444	      { mergedOrderId: merged!._id, sourceOrders: orderIds, userId },
445	      'Orders merged'
446	    );
447	
448	    return merged;
449	  } finally {
450	    await session.endSession();
451	  }
452	}
