15	function simulateCancelWithCompensation(order, db) {
16	  const compensationLog = [];
17	
18	  // 1. Release vehicles back to available
19	  for (const item of order.items) {
20	    const vehicle = db.vehicles.get(item.vehicleId);
21	    if (vehicle) {
22	      const oldStatus = vehicle.status;
23	      vehicle.status = 'available';
24	      compensationLog.push({ type: 'vehicle_released', vehicleId: item.vehicleId, from: oldStatus, to: 'available' });
25	    }
26	  }
27	
28	  // 2. Refund completed payments
29	  const orderPayments = db.payments.filter((p) => p.orderId === order._id && p.status === 'completed');
30	  for (const payment of orderPayments) {
31	    payment.status = 'refunded';
32	    payment.metadata = { ...payment.metadata, refundReason: 'Order cancelled' };
33	
34	    // Reverse wallet transactions
35	    db.walletTxs.push({
36	      debitAccountId: `dealership:${payment.dealershipId}`,
37	      creditAccountId: `buyer:${order.buyerId}`,
38	      amount: payment.amount,
39	      referenceType: 'refund',
40	      referenceId: payment._id,
41	    });
42	
43	    compensationLog.push({ type: 'payment_refunded', paymentId: payment._id, amount: payment.amount });
44	  }
45	
46	  // 3. Void unpaid invoices
47	  const orderInvoices = db.invoices.filter(
48	    (i) => i.orderId === order._id && (i.status === 'issued' || i.status === 'draft')
49	  );
50	  for (const invoice of orderInvoices) {
51	    invoice.status = 'voided';
52	    compensationLog.push({ type: 'invoice_voided', invoiceId: invoice._id });
53	  }
54	
55	  // 4. Update order
56	  order.status = 'cancelled';
57	  order.cancelledAt = new Date();
58	  order.cancelReason = 'Cancelled with full compensation';
59	
60	  db.events.push({
61	    orderId: order._id,
62	    fromStatus: 'reserved',
63	    toStatus: 'cancelled',
64	    reason: 'Cancelled with full compensation',
65	  });
