70	function simulateTimeoutRollback(order, failedEvent, db) {
71	  const compensationLog = [];
72	
73	  // Restore order to pre-transition state
74	  const originalStatus = order.status;
75	
76	  // Compensate vehicle status changes from failed transition
77	  if (failedEvent === 'CANCEL') {
78	    for (const item of order.items) {
79	      const vehicle = db.vehicles.get(item.vehicleId);
80	      if (vehicle && vehicle.status === 'available') {
81	        vehicle.status = 'reserved';
82	        compensationLog.push({ type: 'vehicle_re-reserved', vehicleId: item.vehicleId });
83	      }
84	    }
85	  }
86	  if (failedEvent === 'FULFILL') {
87	    for (const item of order.items) {
88	      const vehicle = db.vehicles.get(item.vehicleId);
89	      if (vehicle && vehicle.status === 'sold') {
90	        vehicle.status = 'reserved';
91	        compensationLog.push({ type: 'vehicle_unreserved', vehicleId: item.vehicleId });
92	      }
93	    }
94	  }
95	
96	  db.events.push({
97	    orderId: order._id,
98	    fromStatus: order.status,
99	    toStatus: originalStatus,
100	    reason: 'Timeout rollback with compensation',
101	    rolledBack: true,
102	    rolledBackAt: new Date(),
103	  });
104	
105	  return compensationLog;
106	}
