5	const DEFAULT_PERMISSIONS = {
6	  document: {
7	    admin: ['read', 'write', 'delete', 'download', 'share', 'submit', 'approve'],
8	    dealership_staff: ['read', 'write', 'delete', 'download', 'share', 'submit'],
9	    finance_reviewer: ['read', 'download', 'submit', 'approve'],
