71	async function hasRetainedFinancialRecords(userId: string): Promise<boolean> {
72	  const retentionCutoff = new Date(Date.now() - FINANCIAL_RETENTION_DAYS * 24 * 60 * 60 * 1000);
73	
74	  const [orderCount, paymentCount] = await Promise.all([
75	    Order.countDocuments({
76	      buyerId: userId,
77	      createdAt: { $gt: retentionCutoff },
78	    }),
79	    Payment.countDocuments({
80	      'metadata.userId': userId,
81	      createdAt: { $gt: retentionCutoff },
82	    }),
83	  ]);
84	
85	  return orderCount > 0 || paymentCount > 0;
86	}
87	
88	async function anonymizeForFinancialRetention(userId: string) {
89	  // Keep the user record but ensure all PII is scrubbed
90	  // Financial records (orders, invoices, payments, wallet transactions)
91	  // retain their references to this userId for audit/compliance purposes
92	  await User.findByIdAndUpdate(userId, {
93	    email: `deleted-${userId}@redacted.local`,
94	    refreshToken: null,
95	    'profile.firstName': '[DELETED]',
96	    'profile.lastName': '[DELETED]',
97	    'profile.phone': '',
98	    'profile.driversLicense': '',
99	    'profile.driversLicenseEncrypted': null,
100	    'profile.ssn': '',
101	    'profile.ssnEncrypted': null,
102	  });
103	
104	  logger.info({ userId }, 'User anonymized for financial retention compliance');
105	}
106	
107	export async function purgeExpiredFinancialRecords() {
108	  const retentionCutoff = new Date(Date.now() - FINANCIAL_RETENTION_DAYS * 24 * 60 * 60 * 1000);
109	
110	  // Only purge financial records older than the retention period
111	  // for users who have already been marked for deletion
112	  const deletedUsers = await User.find({
113	    pendingPurge: true,
114	    email: { $regex: /^deleted-.*@redacted\.local$/ },
115	  });
116	
117	  let purgedCount = 0;
118	
119	  for (const user of deletedUsers) {
120	    const userId = user._id.toString();
121	
122	    const remainingFinancials = await Order.countDocuments({
123	      buyerId: userId,
124	      createdAt: { $gt: retentionCutoff },
125	    });
126	
127	    if (remainingFinancials === 0) {
128	      // All financial records are past retention - safe to fully purge
129	      await Promise.all([
130	        WalletTransaction.deleteMany({
131	          accountId: `buyer:${userId}`,
132	          createdAt: { $lte: retentionCutoff },
133	        }),
134	        User.findByIdAndDelete(userId),
135	      ]);
136	      purgedCount++;
137	      logger.info({ userId }, 'Fully purged user after financial retention period');
138	    }
139	  }
140	
141	  return purgedCount;
142	}
