1	import { Request, Response, NextFunction } from 'express';
2	import { Role } from '../types/enums';
3	
4	interface MaskRule {
5	  field: string;
6	  visibleChars: number;
7	  allowedRoles: Role[];
8	}
9	
10	const MASK_RULES: MaskRule[] = [
11	  {
12	    field: 'driversLicense',
13	    visibleChars: 4,
14	    allowedRoles: [Role.ADMIN, Role.FINANCE_REVIEWER],
15	  },
16	  {
17	    field: 'ssn',
18	    visibleChars: 4,
19	    allowedRoles: [Role.ADMIN, Role.FINANCE_REVIEWER],
20	  },
21	  {
22	    field: 'phone',
23	    visibleChars: 4,
24	    allowedRoles: [Role.ADMIN, Role.DEALERSHIP_STAFF, Role.FINANCE_REVIEWER],
25	  },
26	];
27	
28	function maskValue(value: string, visibleChars: number): string {
29	  if (value.length <= visibleChars) return value;
30	  const visible = value.slice(-visibleChars);
31	  const masked = '*'.repeat(value.length - visibleChars);
32	  return masked + visible;
33	}
34	
35	function applyMask(obj: any, role: Role): any {
36	  if (!obj || typeof obj !== 'object') return obj;
37	  if (Array.isArray(obj)) {
38	    return obj.map((item) => applyMask(item, role));
39	  }
40	
41	  for (const rule of MASK_RULES) {
42	    if (obj[rule.field] && typeof obj[rule.field] === 'string' && !rule.allowedRoles.includes(role)) {
43	      obj[rule.field] = maskValue(obj[rule.field], rule.visibleChars);
44	    }
45	  }
46	
47	  for (const key of Object.keys(obj)) {
48	    if (typeof obj[key] === 'object' && obj[key] !== null && !Array.isArray(obj[key]) && !(obj[key] instanceof Date)) {
49	      applyMask(obj[key], role);
50	    }
51	  }
52	
53	  return obj;
54	}
55	
56	export function fieldMask(req: Request, res: Response, next: NextFunction): void {
57	  const originalJson = res.json.bind(res);
58	
59	  res.json = function (body: any) {
60	    if (req.user && body) {
61	      const serialized = JSON.parse(JSON.stringify(body));
62	      return originalJson(applyMask(serialized, req.user.role as Role));
63	    }
64	    return originalJson(body);
65	  };
66	
67	  next();
68	}
