3	import config from '../config';
4	import { UnauthorizedError } from '../lib/errors';
5	
6	export function authenticate(req: Request, _res: Response, next: NextFunction): void {
7	  try {
8	    const authHeader = req.headers.authorization;
9	    if (!authHeader || !authHeader.startsWith('Bearer ')) {
10	      throw new UnauthorizedError('No token provided');
11	    }
12	
13	    const token = authHeader.split(' ')[1];
14	    const decoded = jwt.verify(token, config.jwtSecret) as {
15	      id: string;
16	      email: string;
17	      role: string;
18	      dealershipId: string | null;
19	    };
20	
21	    req.user = {
22	      id: decoded.id,
23	      email: decoded.email,
24	      role: decoded.role as any,
25	      dealershipId: decoded.dealershipId,
26	    };
27	
28	    next();
29	  } catch (error) {
30	    if (error instanceof UnauthorizedError) {
31	      next(error);
32	      return;
33	    }
34	    next(new UnauthorizedError('Invalid or expired token'));
35	  }
36	}
37	
38	export function optionalAuth(req: Request, _res: Response, next: NextFunction): void {
39	  const authHeader = req.headers.authorization;
40	  if (!authHeader || !authHeader.startsWith('Bearer ')) {
41	    next();
42	    return;
43	  }
44	
45	  try {
46	    const token = authHeader.split(' ')[1];
47	    const decoded = jwt.verify(token, config.jwtSecret) as any;
48	    req.user = {
49	      id: decoded.id,
50	      email: decoded.email,
51	      role: decoded.role,
52	      dealershipId: decoded.dealershipId,
53	    };
54	  } catch {
55	    // Token invalid, proceed without auth
56	  }
57	  next();
58	}
