15	export async function getCart(userId: string, dealershipId: string) {
16	  let cart = await Cart.findOne({ userId, dealershipId }).populate('items.vehicleId');
17	  if (!cart) {
18	    cart = new Cart({ userId, dealershipId, items: [] });
19	    await cart.save();
20	  }
