24	export async function addToCart(
25	  userId: string,
26	  dealershipId: string,
27	  vehicleId: string,
28	  addOnServices: Array<{ serviceCode: string }> = []
29	) {
30	  const vehicle = await Vehicle.findById(vehicleId);
31	  if (!vehicle) throw new NotFoundError('Vehicle not found');
32	  if (vehicle.status !== VehicleStatus.AVAILABLE) {
33	    throw new BadRequestError('Vehicle is not available');
34	  }
35	
36	  let cart = await Cart.findOne({ userId, dealershipId });
37	  if (!cart) {
38	    cart = new Cart({ userId, dealershipId, items: [] });
39	  }
40	
41	  const alreadyInCart = cart.items.some(
42	    (item) => item.vehicleId.toString() === vehicleId
43	  );
44	  if (alreadyInCart) {
45	    throw new BadRequestError('Vehicle already in cart');
46	  }
47	
48	  const addOns = addOnServices
49	    .map((a) => AVAILABLE_ADDONS.find((ao) => ao.serviceCode === a.serviceCode))
50	    .filter(Boolean) as typeof AVAILABLE_ADDONS;
51	
52	  cart.items.push({
53	    vehicleId: vehicle._id as any,
54	    addOnServices: addOns,
55	    addedAt: new Date(),
56	  });
57	
58	  await cart.save();
59	  return Cart.findById(cart._id).populate('items.vehicleId');
60	}
