62	export async function removeFromCart(
63	  userId: string,
64	  dealershipId: string,
65	  vehicleId: string
66	) {
67	  const cart = await Cart.findOne({ userId, dealershipId });
68	  if (!cart) throw new NotFoundError('Cart not found');
69	
70	  cart.items = cart.items.filter(
71	    (item) => item.vehicleId.toString() !== vehicleId
72	  );
73	
74	  await cart.save();
75	  return Cart.findById(cart._id).populate('items.vehicleId');
76	}
