12	export async function uploadDocument(
13	  file: Express.Multer.File,
14	  metadata: {
15	    dealershipId: string;
16	    uploadedBy: string;
17	    type: string;
18	    orderId?: string;
19	    vehicleId?: string;
20	    sensitiveFlag?: boolean;
21	  }
22	) {
23	  validateFileSize(file.size);
24	
25	  let quarantined = false;
26	  let quarantineReason: string | null = null;
27	
