121	  if (filters.orderId) query.orderId = filters.orderId;
122	  if (filters.uploadedBy) query.uploadedBy = filters.uploadedBy;
123	  if (filters.type) query.type = filters.type;
124	
125	  const sort: any = { [pagination.sortBy]: pagination.sortOrder === 'asc' ? 1 : -1 };
126	  const skip = (pagination.page - 1) * pagination.limit;
127	
128	  const [data, total] = await Promise.all([
129	    DocumentModel.find(query).sort(sort).skip(skip).limit(pagination.limit),
130	    DocumentModel.countDocuments(query),
131	  ]);
132	
133	  return buildPaginatedResult(data, total, pagination);
134	}
