15	export async function createOrder(req: Request, res: Response, next: NextFunction) {
16	  try {
17	    const dealershipId = req.user!.role === 'admin'
18	      ? req.scope?.dealershipId
19	      : (req.user!.dealershipId || req.scope?.dealershipId);
20	    if (!dealershipId) {
21	      throw new BadRequestError('dealershipId is required. Admin must use X-Dealership-Id header.');
22	    }
23	    const idempotencyKey = req.body.idempotencyKey || req.headers['x-idempotency-key'] as string;
24	    const result = await orderService.createOrderFromCart(req.user!.id, dealershipId, idempotencyKey);
25	    const orders = Array.isArray(result) ? result : [result];
26	    for (const order of orders) {
27	      await logAuditEvent({
28	        dealershipId,
29	        userId: req.user!.id,
30	        role: req.user!.role,
31	        ip: req.ip || '',
32	        action: 'order.create',
33	        resourceType: 'order',
34	        resourceId: order._id?.toString() || '',
35	        after: { orderNumber: order.orderNumber, status: order.status, totals: order.totals },
36	        requestId: (req as any).requestId,
37	      });
38	    }
39	    res.status(201).json(result);
40	  } catch (error) {
41	    next(error);
42	  }
43	}
