144	export async function listDiscrepancyTickets(req: Request, res: Response, next: NextFunction) {
145	  try {
146	    const pagination = parsePaginationParams(req.query);
147	    const query: any = {};
148	    if (req.query.dealershipId) query.dealershipId = req.query.dealershipId;
149	    else if (req.scope?.dealershipId) query.dealershipId = req.scope.dealershipId;
150	    if (req.query.status) query.status = req.query.status;
151	    if (req.query.type) query.type = req.query.type;
152	    if (req.query.assignedTo) query.assignedTo = req.query.assignedTo;
153	
154	    const skip = (pagination.page - 1) * pagination.limit;
155	    const [data, total] = await Promise.all([
156	      DiscrepancyTicket.find(query).sort({ createdAt: -1 }).skip(skip).limit(pagination.limit),
157	      DiscrepancyTicket.countDocuments(query),
158	    ]);
159	    res.json(buildPaginatedResult(data, total, pagination));
160	  } catch (error) {
161	    next(error);
162	  }
163	}
