8	export async function uploadDocument(req: Request, res: Response, next: NextFunction) {
9	  try {
10	    if (!req.file) {
11	      res.status(400).json({ code: 400, msg: 'No file provided' });
12	      return;
13	    }
14	
15	    const dealershipId = req.user!.role === 'admin'
16	      ? req.scope?.dealershipId
17	      : (req.user!.dealershipId || req.scope?.dealershipId);
18	    if (!dealershipId) {
19	      res.status(400).json({ code: 400, msg: 'Dealership context required' });
20	      return;
21	    }
22	    const doc = await documentService.uploadDocument(req.file, {
23	      dealershipId,
24	      uploadedBy: req.user!.id,
25	      type: req.body.type || 'other',
26	      orderId: req.body.orderId,
27	      vehicleId: req.body.vehicleId,
28	      sensitiveFlag: req.body.sensitiveFlag === 'true',
29	    });
30	
31	    await logAuditEvent({
32	      dealershipId,
33	      userId: req.user!.id,
34	      role: req.user!.role,
35	      ip: req.ip || '',
36	      action: 'document.upload',
37	      resourceType: 'document',
38	      resourceId: doc._id?.toString() || '',
39	      after: { filename: doc.originalFilename, type: doc.type, sensitiveFlag: doc.sensitiveFlag, quarantined: doc.quarantined },
40	      requestId: (req as any).requestId,
41	    });
42	
43	    res.status(201).json(doc);
44	  } catch (error) {
45	    next(error);
