34	export function sanitizeForAudit(data: Record<string, any> | null | undefined): Record<string, any> | null {
35	  if (!data) return null;
36	  const sanitized = { ...data };
37	  for (const key of Object.keys(sanitized)) {
38	    if (SENSITIVE_PATTERNS.some((p) => key.toLowerCase().includes(p.toLowerCase()))) {
39	      sanitized[key] = '[REDACTED]';
40	    }
41	    if (sanitized[key] && typeof sanitized[key] === 'object' && !Array.isArray(sanitized[key])) {
42	      sanitized[key] = sanitizeForAudit(sanitized[key]);
43	    }
