1	import axios from 'axios';
2	
3	const API_BASE = '/api/v1';
4	const HMAC_SECRET = import.meta.env.VITE_HMAC_SECRET || 'aG1hYyBzaGFyZWQgc2VjcmV0IGtleSBmb3IgcmVxdWVzdCBzaWdu';
5	
6	// Routes that require HMAC signing
7	const HMAC_ROUTE_PREFIXES = ['/cart', '/orders', '/documents', '/finance', '/admin', '/privacy'];
8	
9	function needsHmac(url: string): boolean {
10	  const path = url.startsWith(API_BASE) ? url.slice(API_BASE.length) : url;
11	  return HMAC_ROUTE_PREFIXES.some((prefix) => path.startsWith(prefix));
12	}
13	
14	async function generateHmac(
15	  method: string,
16	  path: string,
17	  body: string,
18	  timestamp: string,
19	  secret: string
20	): Promise<string> {
21	  const encoder = new TextEncoder();
22	  const key = await crypto.subtle.importKey(
23	    'raw',
24	    encoder.encode(secret),
25	    { name: 'HMAC', hash: 'SHA-256' },
26	    false,
27	    ['sign']
28	  );
29	  const payload = `${method.toUpperCase()}\n${path}\n${body}\n${timestamp}`;
30	  const signature = await crypto.subtle.sign('HMAC', key, encoder.encode(payload));
31	  return Array.from(new Uint8Array(signature))
32	    .map((b) => b.toString(16).padStart(2, '0'))
33	    .join('');
34	}
35	
36	const httpClient = axios.create({
37	  baseURL: API_BASE,
38	  headers: { 'Content-Type': 'application/json' },
39	});
40	
41	httpClient.interceptors.request.use(async (config) => {
42	  const token = localStorage.getItem('accessToken');
43	  if (token) {
44	    config.headers.Authorization = `Bearer ${token}`;
45	  }
46	
47	  const timestamp = new Date().toISOString();
48	  config.headers['X-Timestamp'] = timestamp;
49	
50	  const fullUrl = config.baseURL
51	    ? `${config.baseURL}${config.url || ''}`
52	    : config.url || '';
53	
54	  if (needsHmac(fullUrl)) {
55	    const method = (config.method || 'GET').toUpperCase();
56	    // Build the path as the server sees it (includes query string)
57	    let path = fullUrl;
58	    if (config.params) {
59	      const qs = new URLSearchParams(config.params).toString();
60	      if (qs) path = `${path}?${qs}`;
61	    }
62	    const body = config.data ? (typeof config.data === 'string' ? config.data : JSON.stringify(config.data)) : '';
63	    config.headers['X-Hmac-Signature'] = await generateHmac(method, path, body, timestamp, HMAC_SECRET);
64	  }
65	
66	  return config;
67	});
68	
69	httpClient.interceptors.response.use(
70	  (response) => response,
71	  async (error) => {
72	    if (error.response?.status === 401) {
73	      const refreshToken = localStorage.getItem('refreshToken');
74	      if (refreshToken && !error.config._retry) {
75	        error.config._retry = true;
76	        try {
77	          const { data } = await axios.post(`${API_BASE}/auth/refresh`, { refreshToken });
78	          localStorage.setItem('accessToken', data.accessToken);
79	          localStorage.setItem('refreshToken', data.refreshToken);
80	          error.config.headers.Authorization = `Bearer ${data.accessToken}`;
81	          return httpClient(error.config);
82	        } catch {
83	          localStorage.removeItem('accessToken');
84	          localStorage.removeItem('refreshToken');
85	          window.location.href = '/login';
86	        }
87	      }
88	    }
89	    return Promise.reject(error);
90	  }
91	);
92	
93	export default httpClient;
