3	// Uses the same permission resolution logic as production permission.service.ts
4	
5	const DEFAULT_PERMISSIONS = {
6	  document: {
7	    admin: ['read', 'write', 'delete', 'download', 'share', 'submit', 'approve'],
8	    dealership_staff: ['read', 'write', 'delete', 'download', 'share', 'submit'],
9	    finance_reviewer: ['read', 'download', 'submit', 'approve'],
10	    buyer: ['read', 'download'],
11	  },
12	};
13	
14	function checkPermission(userId, role, resource, resourceId, action, sensitiveFlag, overrides) {
15	  if (role === 'admin') return true;
16	
17	  if (sensitiveFlag && role !== 'finance_reviewer' && role !== 'admin') {
18	    const override = overrides.find(
19	      (o) => o.effect === 'allow' && o.actions.includes(action) && (o.userId === userId || o.userId === null)
20	    );
21	    return !!override;
22	  }
23	
24	  // Check user-specific overrides first
25	  const userOverride = overrides.find(
26	    (o) => o.userId === userId && o.resourceId === resourceId && o.actions.includes(action)
27	  );
28	  if (userOverride) return userOverride.effect === 'allow';
29	
30	  // Check role overrides
31	  const roleOverride = overrides.find(
32	    (o) => o.role === role && o.userId === null && o.resourceId === resourceId && o.actions.includes(action)
33	  );
34	  if (roleOverride) return roleOverride.effect === 'allow';
35	
36	  const resourceDefaults = DEFAULT_PERMISSIONS[resource];
37	  if (!resourceDefaults) return false;
38	  const roleDefaults = resourceDefaults[role];
39	  if (!roleDefaults) return false;
40	  return roleDefaults.includes(action);
41	}
