14	// Uses production verifyHmac for actual signature verification
15	function simulateHmacVerify(headers, method, path, body, secret, windowSeconds, nonceStore) {
16	  const signature = headers['x-hmac-signature'];
17	  const timestamp = headers['x-timestamp'];
18	
19	  if (!signature || !timestamp) return { ok: false, code: 401, msg: 'Missing HMAC signature or timestamp' };
20	
21	  // Input guard: signature must be valid 64-char hex
22	  if (!/^[0-9a-fA-F]{64}$/.test(signature)) return { ok: false, code: 401, msg: 'Invalid HMAC signature format' };
23	
24	  const requestTime = new Date(timestamp).getTime();
25	  if (isNaN(requestTime)) return { ok: false, code: 401, msg: 'Invalid timestamp format' };
26	
27	  const now = Date.now();
28	  const drift = Math.abs(now - requestTime) / 1000;
29	  if (drift > windowSeconds) return { ok: false, code: 401, msg: 'Request timestamp outside acceptable window' };
30	
31	  const valid = verifyHmac(signature, method, path, body, timestamp, secret);
32	  if (!valid) return { ok: false, code: 401, msg: 'Invalid HMAC signature' };
33	
34	  const nonceKey = `hmac:nonce:${signature}`;
35	  if (nonceStore.has(nonceKey)) return { ok: false, code: 409, msg: 'Replay detected' };
36	  nonceStore.add(nonceKey);
37	
38	  return { ok: true };
39	}
