33	function request(method, path, body, token, opts) {
34	  return new Promise((resolve, reject) => {
35	    const url = new URL(path, BASE_URL);
36	    const fullPath = url.pathname + url.search;
37	    const timestamp = (opts && opts.timestamp) || new Date().toISOString();
38	    const bodyStr = body ? JSON.stringify(body) : '';
39	
40	    const options = {
41	      hostname: url.hostname,
42	      port: url.port,
43	      path: fullPath,
44	      method,
45	      headers: {
46	        'Content-Type': 'application/json',
47	        'X-Timestamp': timestamp,
48	      },
49	    };
50	
51	    if (!(opts && opts.skipHmac)) {
52	      const signature = generateHmac(method, fullPath, bodyStr, timestamp, HMAC_SECRET);
53	      options.headers['X-Hmac-Signature'] = signature;
54	    }
55	
56	    if (opts && opts.headers) {
57	      Object.assign(options.headers, opts.headers);
58	    }
59	
60	    if (token) options.headers['Authorization'] = `Bearer ${token}`;
61	
62	    const req = http.request(options, (res) => {
63	      let data = '';
64	      res.on('data', (chunk) => { data += chunk; });
65	      res.on('end', () => {
66	        let parsed;
67	        try { parsed = JSON.parse(data); } catch { parsed = data; }
68	        resolve({ status: res.statusCode, data: parsed });
69	      });
70	    });
71	
72	    req.on('error', reject);
73	    if (body) req.write(JSON.stringify(body));
74	    req.end();
75	  });
76	}
