358	function waitForServer(retries = 30, delay = 2000) {
359	  return new Promise((resolve, reject) => {
360	    function attempt(n) {
361	      request('GET', '/api/v1/health')
362	        .then((res) => {
363	          if (res.status === 200) resolve();
364	          else if (n <= 0) reject(new Error('Server not ready'));
365	          else setTimeout(() => attempt(n - 1), delay);
366	        })
367	        .catch(() => {
368	          if (n <= 0) reject(new Error('Server not reachable'));
369	          else setTimeout(() => attempt(n - 1), delay);
370	        });
371	    }
372	    attempt(retries);
373	  });
374	}
375	
376	waitForServer()
377	  .then(() => runTests())
378	  .catch((e) => { console.error('Failed to connect to server:', e.message); process.exit(1); });
