1	import { StateMachine, StateMachineDefinition } from '../../lib/state-machine';
2	import { OrderStatus, OrderEvent } from '../../types/enums';
3	
4	export const orderStateMachineDefinition: StateMachineDefinition<OrderStatus, OrderEvent> = {
5	  initial: OrderStatus.CREATED,
6	  transitions: [
7	    { from: OrderStatus.CREATED, event: OrderEvent.RESERVE, to: OrderStatus.RESERVED },
8	    { from: OrderStatus.CREATED, event: OrderEvent.CANCEL, to: OrderStatus.CANCELLED },
9	    { from: OrderStatus.RESERVED, event: OrderEvent.INVOICE, to: OrderStatus.INVOICED },
10	    { from: OrderStatus.RESERVED, event: OrderEvent.CANCEL, to: OrderStatus.CANCELLED },
11	    { from: OrderStatus.INVOICED, event: OrderEvent.SETTLE, to: OrderStatus.SETTLED },
12	    { from: OrderStatus.INVOICED, event: OrderEvent.CANCEL, to: OrderStatus.CANCELLED },
13	    { from: OrderStatus.SETTLED, event: OrderEvent.FULFILL, to: OrderStatus.FULFILLED },
14	    { from: OrderStatus.SETTLED, event: OrderEvent.CANCEL, to: OrderStatus.CANCELLED },
15	  ],
16	};
17	
18	export function createOrderStateMachine(currentStatus?: OrderStatus): StateMachine<OrderStatus, OrderEvent> {
19	  return new StateMachine(orderStateMachineDefinition, currentStatus);
20	}
21

1	export interface Transition<S extends string, E extends string> {
2	  from: S | S[];
3	  event: E;
4	  to: S;
5	  guard?: (context: any) => boolean | Promise<boolean>;
6	}
7	
8	export interface StateMachineDefinition<S extends string, E extends string> {
9	  initial: S;
10	  transitions: Transition<S, E>[];
11	}
12	
13	export class StateMachine<S extends string, E extends string> {
14	  private definition: StateMachineDefinition<S, E>;
15	  private currentState: S;
16	
17	  constructor(definition: StateMachineDefinition<S, E>, currentState?: S) {
18	    this.definition = definition;
19	    this.currentState = currentState || definition.initial;
20	  }
21	
22	  getState(): S {
23	    return this.currentState;
24	  }
25	
26	  can(event: E): boolean {
27	    return this.definition.transitions.some(
28	      (t) =>
29	        (Array.isArray(t.from) ? t.from.includes(this.currentState) : t.from === this.currentState) &&
30	        t.event === event
31	    );
32	  }
33	
34	  getAvailableEvents(): E[] {
35	    return this.definition.transitions
36	      .filter((t) =>
37	        Array.isArray(t.from) ? t.from.includes(this.currentState) : t.from === this.currentState
38	      )
39	      .map((t) => t.event);
40	  }
41	
42	  async transition(event: E, context?: any): Promise<{ from: S; to: S }> {
43	    const transition = this.definition.transitions.find(
44	      (t) =>
45	        (Array.isArray(t.from) ? t.from.includes(this.currentState) : t.from === this.currentState) &&
46	        t.event === event
47	    );
48	
49	    if (!transition) {
50	      throw new Error(
51	        `Invalid transition: cannot apply event "${event}" in state "${this.currentState}"`
52	      );
53	    }
54	
55	    if (transition.guard) {
56	      const allowed = await transition.guard(context);
57	      if (!allowed) {
58	        throw new Error(
59	          `Guard rejected transition: "${event}" from "${this.currentState}"`
60	        );
61	      }
62	    }
63	
64	    const from = this.currentState;
65	    this.currentState = transition.to;
66	    return { from, to: transition.to };
67	  }
68	}
