38	export function optionalAuth(req: Request, _res: Response, next: NextFunction): void {
39	  const authHeader = req.headers.authorization;
40	  if (!authHeader || !authHeader.startsWith('Bearer ')) {
41	    next();
42	    return;
43	  }
44	
45	  try {
46	    const token = authHeader.split(' ')[1];
47	    const decoded = jwt.verify(token, config.jwtSecret) as any;
48	    req.user = {
49	      id: decoded.id,
50	      email: decoded.email,
51	      role: decoded.role,
52	      dealershipId: decoded.dealershipId,
53	    };
54	  } catch {
55	    // Token invalid, proceed without auth
56	  }
57	  next();
58	}
