37	  const subDir = `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}`;
38	
39	  let storagePath: string;
40	  if (quarantined) {
41	    const quarantineDir = path.join(config.quarantineDir, metadata.dealershipId);
42	    fs.mkdirSync(quarantineDir, { recursive: true });
43	    storagePath = path.join(quarantineDir, `${sha256Hash}-${file.originalname}`);
44	  } else {
45	    const uploadDir = path.join(config.uploadDir, metadata.dealershipId, subDir);
46	    fs.mkdirSync(uploadDir, { recursive: true });
47	    storagePath = path.join(uploadDir, `${sha256Hash}-${file.originalname}`);
48	  }
49	
50	  fs.writeFileSync(storagePath, file.buffer);
51	
52	  let encryptedMetadata = null;
53	  if (metadata.sensitiveFlag) {
54	    encryptedMetadata = {
55	      originalFilename: await encryptValue(file.originalname),
56	      storagePath: await encryptValue(storagePath),
57	    };
58	  }
59	
60	  const doc = new DocumentModel({
61	    dealershipId: metadata.dealershipId,
62	    orderId: metadata.orderId || null,
63	    vehicleId: metadata.vehicleId || null,
64	    uploadedBy: metadata.uploadedBy,
65	    type: metadata.type,
66	    originalFilename: file.originalname,
67	    storagePath,
68	    mimeType: file.mimetype,
69	    sizeBytes: file.size,
70	    sha256Hash,
71	    quarantined,
72	    quarantineReason,
73	    sensitiveFlag: metadata.sensitiveFlag || false,
74	    encryptedMetadata,
75	  });
76	
77	  await doc.save();
78	
79	  logger.info(
80	    { documentId: doc._id, quarantined, filename: file.originalname },
81	    'Document uploaded'
82	  );
83	
84	  return doc;
85	}
