93	export async function downloadDocument(documentId: string) {
94	  const doc = await DocumentModel.findById(documentId);
95	  if (!doc) throw new NotFoundError('Document not found');
96	  if (doc.quarantined) throw new ForbiddenError('Document is quarantined');
97	
98	  if (!fs.existsSync(doc.storagePath)) {
99	    throw new NotFoundError('Document file not found on disk');
100	  }
101	
102	  const buffer = fs.readFileSync(doc.storagePath);
103	  const currentHash = hashFile(buffer);
104	
105	  if (currentHash !== doc.sha256Hash) {
106	    doc.quarantined = true;
107	    doc.quarantineReason = 'Hash mismatch on download - possible tampering';
108	    await doc.save();
109	    throw new ForbiddenError('Document integrity check failed - quarantined');
110	  }
111	
112	  return { buffer, mimeType: doc.mimeType, filename: doc.originalFilename };
113	}
