16	function generateOrderNumber(dealershipId: string): string {
17	  const prefix = dealershipId.slice(-4).toUpperCase();
18	  const ts = Date.now().toString(36).toUpperCase();
19	  return `ORD-${prefix}-${ts}`;
20	}
