22	export async function createOrderFromCart(
23	  userId: string,
24	  dealershipId: string,
25	  idempotencyKey: string
26	) {
27	  const existing = await Order.findOne({ idempotencyKey });
28	  if (existing) return existing;
29	
30	  const cart = await Cart.findOne({ userId, dealershipId }).populate('items.vehicleId');
31	  if (!cart || cart.items.length === 0) {
32	    throw new BadRequestError('Cart is empty');
33	  }
34	
35	  const groups = new Map<string, typeof cart.items>();
36	
37	  for (const item of cart.items) {
38	    const vehicle = item.vehicleId as any;
39	    const groupKey = `${vehicle.supplierId || 'default'}|${vehicle.warehouseId || 'default'}|${vehicle.estimatedTurnaround <= 1 ? 'same-day' : 'standard'}`;
40	
41	    if (!groups.has(groupKey)) {
42	      groups.set(groupKey, []);
43	    }
44	    groups.get(groupKey)!.push(item);
45	  }
46	
47	  const orders: IOrder[] = [];
48	  const session = await mongoose.startSession();
49	
50	  try {
51	    await session.withTransaction(async () => {
52	      for (const [, groupItems] of groups) {
53	        const orderItems = [];
54	        let subtotal = 0;
55	
56	        for (const item of groupItems) {
57	          const vehicle = await Vehicle.findById(item.vehicleId).session(session);
58	          if (!vehicle || vehicle.status !== VehicleStatus.AVAILABLE) {
59	            throw new BadRequestError(`Vehicle ${item.vehicleId} is no longer available`);
60	          }
61	
62	          vehicle.status = VehicleStatus.RESERVED;
63	          await vehicle.save({ session });
64	
65	          const addOnTotal = item.addOnServices.reduce((sum, a) => sum + a.price, 0);
66	          const itemSubtotal = vehicle.price + addOnTotal;
67	          subtotal += itemSubtotal;
68	
69	          orderItems.push({
70	            vehicleId: vehicle._id,
71	            supplierId: vehicle.supplierId,
72	            warehouseId: vehicle.warehouseId,
73	            turnaroundDays: vehicle.estimatedTurnaround,
74	            addOnServices: item.addOnServices,
75	            subtotal: itemSubtotal,
76	          });
77	        }
78	
79	        const orderKey = groups.size > 1 ? `${idempotencyKey}-${orders.length}` : idempotencyKey;
80	
81	        const order = new Order({
82	          orderNumber: generateOrderNumber(dealershipId),
83	          dealershipId,
84	          buyerId: userId,
85	          status: OrderStatus.CREATED,
86	          items: orderItems,
87	          totals: { subtotal, tax: 0, total: subtotal },
88	          idempotencyKey: orderKey,
89	        });
90	
91	        await order.save({ session });
92	
93	        await OrderEventModel.create(
94	          [
95	            {
96	              orderId: order._id,
97	              fromStatus: null,
98	              toStatus: OrderStatus.CREATED,
99	              triggeredBy: userId,
100	              reason: 'Order created from cart',
101	            },
102	          ],
103	          { session }
104	        );
105	
106	        orders.push(order);
107	      }
108	
109	      if (orders.length > 1) {
110	        const parentOrder = orders[0];
111	        const childIds = orders.slice(1).map((o) => o._id);
112	        for (const child of orders.slice(1)) {
113	          child.parentOrderId = parentOrder._id as any;
114	          await child.save({ session });
115	        }
116	        parentOrder.childOrderIds = childIds as any;
117	        await parentOrder.save({ session });
118	      }
119	
120	      cart.items = [];
121	      await cart.save({ session });
122	    });
123	  } finally {
124	    await session.endSession();
125	  }
126	
127	  logger.info(
128	    { orderCount: orders.length, userId, dealershipId },
129	    'Orders created from cart'
130	  );
131	
132	  return orders.length === 1 ? orders[0] : orders;
133	}
