163	export async function transitionOrder(
164	  orderId: string,
165	  event: OrderEvent,
166	  userId: string,
167	  reason: string = ''
168	) {
169	  const order = await Order.findById(orderId);
170	  if (!order) throw new NotFoundError('Order not found');
171	
172	  const originalStatus = order.status;
173	  const fsm = createOrderStateMachine(order.status as OrderStatus);
174	
175	  if (!fsm.can(event)) {
176	    throw new BadRequestError(
177	      `Cannot apply "${event}" to order in "${order.status}" status`
178	    );
179	  }
180	
181	  const { from, to } = await fsm.transition(event);
182	  const sagaSteps: SagaStep[] = [];
183	
184	  if (event === OrderEvent.CANCEL) {
185	    // Step 1: Release vehicles
186	    const vehicleUpdates: Array<{ vehicleId: any; prevStatus: string }> = [];
187	    sagaSteps.push({
188	      name: 'release_vehicles',
189	      execute: async () => {
190	        for (const item of order.items) {
191	          const v = await Vehicle.findById(item.vehicleId);
192	          if (v) {
193	            vehicleUpdates.push({ vehicleId: item.vehicleId, prevStatus: v.status });
194	            v.status = VehicleStatus.AVAILABLE;
195	            await v.save();
196	          }
197	        }
198	      },
199	      compensate: async () => {
200	        for (const vu of vehicleUpdates) {
201	          await Vehicle.findByIdAndUpdate(vu.vehicleId, { status: vu.prevStatus });
202	        }
203	      },
204	    });
205	
206	    // Step 2: Refund payments
207	    const refundedPaymentIds: string[] = [];
208	    sagaSteps.push({
209	      name: 'refund_payments',
210	      execute: async () => {
211	        const payments = await Payment.find({ orderId: order._id, status: PaymentStatus.COMPLETED });
212	        for (const payment of payments) {
213	          await refundPayment(payment._id.toString(), reason || 'Order cancelled');
214	          refundedPaymentIds.push(payment._id.toString());
215	        }
216	      },
217	      compensate: async () => {
218	        // Payment refunds are financial records - log but don't reverse
219	        logger.warn({ orderId, refundedPaymentIds }, 'Payment refunds cannot be automatically reversed');
220	      },
221	    });
222	
223	    // Step 3: Void invoices
224	    const voidedInvoices: Array<{ invoiceId: any; prevStatus: string }> = [];
225	    sagaSteps.push({
226	      name: 'void_invoices',
227	      execute: async () => {
228	        const invoices = await Invoice.find({
229	          orderId: order._id,
230	          status: { $in: [InvoiceStatus.ISSUED, InvoiceStatus.DRAFT] },
231	        });
232	        for (const invoice of invoices) {
233	          voidedInvoices.push({ invoiceId: invoice._id, prevStatus: invoice.status });
234	          invoice.status = InvoiceStatus.VOIDED;
235	          await invoice.save();
236	        }
237	      },
238	      compensate: async () => {
239	        for (const vi of voidedInvoices) {
240	          await Invoice.findByIdAndUpdate(vi.invoiceId, { status: vi.prevStatus });
241	        }
242	      },
243	    });
244	
245	    // Step 4: Update order
246	    sagaSteps.push({
247	      name: 'update_order_cancelled',
248	      execute: async () => {
249	        order.cancelledAt = new Date();
250	        order.cancelReason = reason || 'Cancelled by user';
251	        order.status = to;
252	        await order.save();
253	      },
254	      compensate: async () => {
255	        order.status = originalStatus as OrderStatus;
256	        order.cancelledAt = null as any;
257	        order.cancelReason = null as any;
258	        await order.save();
259	      },
260	    });
261	  } else if (event === OrderEvent.FULFILL) {
262	    // Step 1: Mark vehicles sold
263	    const vehicleUpdates: Array<{ vehicleId: any; prevStatus: string }> = [];
264	    sagaSteps.push({
265	      name: 'mark_vehicles_sold',
266	      execute: async () => {
267	        for (const item of order.items) {
268	          const v = await Vehicle.findById(item.vehicleId);
269	          if (v) {
270	            vehicleUpdates.push({ vehicleId: item.vehicleId, prevStatus: v.status });
271	            v.status = VehicleStatus.SOLD;
272	            await v.save();
273	          }
274	        }
275	      },
276	      compensate: async () => {
277	        for (const vu of vehicleUpdates) {
278	          await Vehicle.findByIdAndUpdate(vu.vehicleId, { status: vu.prevStatus });
279	        }
280	      },
281	    });
282	
283	    // Step 2: Update order
284	    sagaSteps.push({
285	      name: 'update_order_status',
286	      execute: async () => {
287	        order.status = to;
288	        await order.save();
289	      },
290	      compensate: async () => {
291	        order.status = originalStatus as OrderStatus;
292	        await order.save();
293	      },
294	    });
295	  } else {
296	    // Simple status transitions (RESERVE, INVOICE, SETTLE)
297	    sagaSteps.push({
298	      name: 'update_order_status',
299	      execute: async () => {
300	        order.status = to;
301	        await order.save();
302	      },
303	      compensate: async () => {
304	        order.status = originalStatus as OrderStatus;
305	        await order.save();
306	      },
307	    });
308	  }
309	
310	  await executeSaga(sagaSteps, orderId);
311	
312	  await OrderEventModel.create({
313	    orderId: order._id,
314	    fromStatus: from,
315	    toStatus: to,
316	    triggeredBy: userId,
317	    reason,
318	  });
319	
320	  logger.info({ orderId, from, to, event, userId }, 'Order transitioned');
321	  return order;
322	}
