10	export async function runReconciliation() {
11	  const dealerships = await Dealership.find({ isActive: true });
12	  const results = [];
13	
14	  for (const dealership of dealerships) {
15	    try {
16	      const result = await reconcileDealership(dealership._id.toString());
17	      results.push(result);
18	    } catch (error: any) {
19	      logger.error(
20	        { dealershipId: dealership._id, error: error.message },
21	        'Reconciliation failed for dealership'
22	      );
23	      results.push(
24	        await ReconciliationRun.create({
25	          dealershipId: dealership._id,
26	          period: {
27	            from: new Date(Date.now() - 24 * 60 * 60 * 1000),
28	            to: new Date(),
29	          },
30	          status: 'failed',
31	          discrepancies: [{ type: 'error', referenceId: dealership._id, details: error.message }],
32	        })
33	      );
34	    }
35	  }
36	
37	  return results;
38	}
