40	async function reconcileDealership(dealershipId: string) {
41	  const periodEnd = new Date();
42	  periodEnd.setHours(0, 0, 0, 0);
43	  const periodStart = new Date(periodEnd.getTime() - 24 * 60 * 60 * 1000);
44	
45	  const orders = await Order.find({
46	    dealershipId,
47	    status: { $in: [OrderStatus.SETTLED, OrderStatus.FULFILLED] },
48	    updatedAt: { $gte: periodStart, $lt: periodEnd },
49	  });
50	
51	  const orderIds = orders.map((o) => o._id);
52	
53	  const invoices = await Invoice.find({
54	    dealershipId,
55	    orderId: { $in: orderIds },
56	    status: { $in: [InvoiceStatus.ISSUED, InvoiceStatus.PAID] },
57	  });
58	
59	  const invoiceIds = invoices.map((i) => i._id);
60	
61	  const payments = await Payment.find({
62	    dealershipId,
63	    invoiceId: { $in: invoiceIds },
64	    status: PaymentStatus.COMPLETED,
65	  });
66	
67	  const invoiceByOrder = new Map(invoices.map((i) => [i.orderId.toString(), i]));
68	  const paymentsByInvoice = new Map<string, typeof payments>();
69	  for (const p of payments) {
70	    const key = p.invoiceId.toString();
71	    if (!paymentsByInvoice.has(key)) paymentsByInvoice.set(key, []);
72	    paymentsByInvoice.get(key)!.push(p);
73	  }
74	
75	  const discrepancies: Array<{ type: string; referenceId: any; details: string }> = [];
76	  const unmatchedOrders: any[] = [];
77	  const unmatchedInvoices: any[] = [];
78	  const unmatchedSettlements: any[] = [];
79	  let matchedCount = 0;
80	
81	  for (const order of orders) {
82	    const invoice = invoiceByOrder.get(order._id.toString());
83	    if (!invoice) {
84	      unmatchedOrders.push(order._id);
85	      discrepancies.push({
86	        type: 'missing_invoice',
87	        referenceId: order._id,
88	        details: `Order ${order.orderNumber} has no invoice`,
89	      });
90	      continue;
91	    }
92	
93	    const orderPayments = paymentsByInvoice.get(invoice._id.toString()) || [];
94	    const paidAmount = orderPayments.reduce((sum, p) => sum + p.amount, 0);
95	
96	    if (orderPayments.length === 0) {
97	      unmatchedInvoices.push(invoice._id);
98	      discrepancies.push({
99	        type: 'unpaid_invoice',
100	        referenceId: invoice._id,
101	        details: `Invoice ${invoice.invoiceNumber} has no payments`,
102	      });
103	    } else if (paidAmount !== invoice.total) {
104	      discrepancies.push({
105	        type: 'amount_mismatch',
106	        referenceId: invoice._id,
107	        details: `Invoice ${invoice.invoiceNumber}: expected ${invoice.total}, paid ${paidAmount}`,
108	      });
109	    } else if (invoice.total !== order.totals.total) {
110	      discrepancies.push({
111	        type: 'order_invoice_mismatch',
112	        referenceId: order._id,
113	        details: `Order ${order.orderNumber} total (${order.totals.total}) != Invoice total (${invoice.total})`,
114	      });
115	    } else {
116	      matchedCount++;
117	    }
118	  }
119	
120	  const status =
121	    discrepancies.length > 0 ? 'completed_with_discrepancies' : 'completed';
122	
123	  const run = await ReconciliationRun.create({
124	    dealershipId,
125	    period: { from: periodStart, to: periodEnd },
126	    matchedCount,
127	    unmatchedOrders,
128	    unmatchedInvoices,
129	    unmatchedSettlements,
130	    discrepancies,
131	    status,
132	  });
133	
134	  // Auto-create discrepancy tickets for manual review
135	  if (discrepancies.length > 0) {
136	    const tickets = discrepancies.map((d) => ({
137	      reconciliationRunId: run._id,
138	      dealershipId,
139	      type: d.type,
140	      referenceId: d.referenceId,
141	      details: d.details,
142	      status: 'open',
143	    }));
144	    await DiscrepancyTicket.insertMany(tickets);
145	    logger.info(
146	      { dealershipId, ticketCount: tickets.length },
147	      'Discrepancy tickets created'
148	    );
149	  }
150	
151	  logger.info(
152	    { dealershipId, matchedCount, discrepancies: discrepancies.length },
153	    'Reconciliation completed'
154	  );
155	
156	  return run;
157	}
