1	import { createContext, useContext, useState, useEffect, ReactNode } from 'react';
2	import httpClient from '../../../shared/api/httpClient';
3	
4	interface User {
5	  _id: string;
6	  email: string;
7	  role: string;
8	  dealershipId: string | null;
9	  profile: {
10	    firstName: string;
11	    lastName: string;
12	    phone?: string;
13	  };
14	}
15	
16	interface AuthState {
17	  user: User | null;
18	  isAuthenticated: boolean;
19	  isLoading: boolean;
20	}
21	
22	interface AuthContextType extends AuthState {
23	  login: (email: string, password: string) => Promise<void>;
24	  register: (data: any) => Promise<void>;
25	  logout: () => void;
26	}
27	
28	const AuthContext = createContext<AuthContextType | null>(null);
29	
30	export function useAuth() {
31	  const ctx = useContext(AuthContext);
32	  if (!ctx) throw new Error('useAuth must be used within AuthProvider');
33	  return ctx;
34	}
35	
36	export function AuthProvider({ children }: { children: ReactNode }) {
37	  const [state, setState] = useState<AuthState>({
38	    user: null,
39	    isAuthenticated: false,
40	    isLoading: true,
41	  });
42	
43	  useEffect(() => {
44	    const token = localStorage.getItem('accessToken');
45	    if (token) {
46	      httpClient
47	        .get('/auth/me')
48	        .then(({ data }) => {
49	          setState({ user: data, isAuthenticated: true, isLoading: false });
50	        })
51	        .catch(() => {
52	          localStorage.removeItem('accessToken');
53	          localStorage.removeItem('refreshToken');
54	          setState({ user: null, isAuthenticated: false, isLoading: false });
55	        });
56	    } else {
57	      setState({ user: null, isAuthenticated: false, isLoading: false });
58	    }
59	  }, []);
60	
61	  const login = async (email: string, password: string) => {
62	    const { data } = await httpClient.post('/auth/login', { email, password });
63	    localStorage.setItem('accessToken', data.accessToken);
64	    localStorage.setItem('refreshToken', data.refreshToken);
65	    setState({ user: data.user, isAuthenticated: true, isLoading: false });
66	  };
67	
68	  const register = async (formData: any) => {
69	    const { data } = await httpClient.post('/auth/register', formData);
70	    localStorage.setItem('accessToken', data.accessToken);
71	    localStorage.setItem('refreshToken', data.refreshToken);
72	    setState({ user: data.user, isAuthenticated: true, isLoading: false });
73	  };
74	
75	  const logout = () => {
76	    httpClient.post('/auth/logout').catch(() => {});
77	    localStorage.removeItem('accessToken');
78	    localStorage.removeItem('refreshToken');
79	    setState({ user: null, isAuthenticated: false, isLoading: false });
80	  };
81	
82	  return (
83	    <AuthContext.Provider value={{ ...state, login, register, logout }}>
84	      {children}
85	    </AuthContext.Provider>
86	  );
87	}
