5	function buildSearchQuery(filters) {
6	  const query = { status: 'available' };
7	
8	  if (filters.dealershipId) query.dealershipId = filters.dealershipId;
9	  if (filters.make) query.make = { $regex: new RegExp(`^${filters.make}$`, 'i') };
10	  if (filters.model) query.model = { $regex: new RegExp(`^${filters.model}$`, 'i') };
11	  if (filters.year) query.year = parseInt(filters.year);
12	
13	  if (filters.minPrice || filters.maxPrice) {
14	    query.price = {};
15	    if (filters.minPrice) query.price.$gte = parseInt(filters.minPrice);
16	    if (filters.maxPrice) query.price.$lte = parseInt(filters.maxPrice);
17	  }
18	
19	  if (filters.minMileage || filters.maxMileage) {
20	    query.mileage = {};
21	    if (filters.minMileage) query.mileage.$gte = parseInt(filters.minMileage);
22	    if (filters.maxMileage) query.mileage.$lte = parseInt(filters.maxMileage);
23	  }
24	
25	  if (filters.region) query.region = { $regex: new RegExp(filters.region, 'i') };
26	
27	  if (filters.minRegistrationDate || filters.maxRegistrationDate) {
28	    query.registrationDate = {};
29	    if (filters.minRegistrationDate) query.registrationDate.$gte = new Date(filters.minRegistrationDate);
30	    if (filters.maxRegistrationDate) query.registrationDate.$lte = new Date(filters.maxRegistrationDate);
31	  }
32	
33	  return query;
34	}
