42	function filterVehicles(vehicles, query) {
43	  return vehicles.filter((v) => {
44	    if (query.status && v.status !== query.status) return false;
45	    if (query.dealershipId && v.dealershipId !== query.dealershipId) return false;
46	    if (query.make && !v.make.match(query.make.$regex)) return false;
47	    if (query.model && !v.model.match(query.model.$regex)) return false;
48	    if (query.year && v.year !== query.year) return false;
49	    if (query.price) {
50	      if (query.price.$gte && v.price < query.price.$gte) return false;
51	      if (query.price.$lte && v.price > query.price.$lte) return false;
52	    }
53	    if (query.mileage) {
54	      if (query.mileage.$gte && v.mileage < query.mileage.$gte) return false;
55	      if (query.mileage.$lte && v.mileage > query.mileage.$lte) return false;
56	    }
57	    if (query.registrationDate) {
58	      const regDate = new Date(v.registrationDate);
59	      if (query.registrationDate.$gte && regDate < query.registrationDate.$gte) return false;
60	      if (query.registrationDate.$lte && regDate > query.registrationDate.$lte) return false;
61	    }
62	    return true;
63	  });
64	}
