30	function request(method, path, body, token, opts) {
31	  return new Promise((resolve, reject) => {
32	    const url = new URL(path, BASE_URL);
33	    const fullPath = url.pathname + url.search;
34	    const timestamp = new Date().toISOString();
35	    const bodyStr = body ? JSON.stringify(body) : '';
36	
37	    const options = {
38	      hostname: url.hostname,
39	      port: url.port,
40	      path: fullPath,
41	      method,
42	      headers: {
43	        'Content-Type': 'application/json',
44	        'X-Timestamp': timestamp,
45	      },
46	    };
47	
48	    // Generate HMAC signature unless explicitly skipped
49	    if (!(opts && opts.skipHmac)) {
50	      const signature = generateHmac(method, fullPath, bodyStr, timestamp, HMAC_SECRET);
51	      options.headers['X-Hmac-Signature'] = signature;
52	    }
53	
54	    // Allow overriding specific headers for testing
55	    if (opts && opts.headers) {
56	      Object.assign(options.headers, opts.headers);
57	    }
58	
59	    if (token) options.headers['Authorization'] = `Bearer ${token}`;
60	
61	    const req = http.request(options, (res) => {
62	      let data = '';
63	      res.on('data', (chunk) => { data += chunk; });
64	      res.on('end', () => {
65	        let parsed;
66	        try { parsed = JSON.parse(data); } catch { parsed = data; }
67	        resolve({ status: res.statusCode, data: parsed });
68	      });
69	    });
70	
71	    req.on('error', reject);
72	    if (body) req.write(JSON.stringify(body));
73	    req.end();
74	  });
75	}
