430	function waitForServer(retries = 30, delay = 2000) {
431	  return new Promise((resolve, reject) => {
432	    function attempt(n) {
433	      request('GET', '/api/v1/health')
434	        .then((res) => {
435	          if (res.status === 200) resolve();
436	          else if (n <= 0) reject(new Error('Server not ready'));
437	          else setTimeout(() => attempt(n - 1), delay);
438	        })
439	        .catch(() => {
440	          if (n <= 0) reject(new Error('Server not reachable'));
441	          else setTimeout(() => attempt(n - 1), delay);
442	        });
443	    }
444	    attempt(retries);
445	  });
446	}
447	
448	waitForServer()
449	  .then(() => runTests())
450	  .catch((e) => { console.error('Failed to connect to server:', e.message); process.exit(1); });
