7	function assertOrderAccess(order: any, req: Request) {
8	  if (req.user!.role === 'admin') return;
9	  const userDealership = req.user!.dealershipId || req.scope?.dealershipId;
10	  if (userDealership && order.dealershipId?.toString() === userDealership) return;
11	  if (order.buyerId?.toString() === req.user!.id || (order.buyerId as any)?._id?.toString() === req.user!.id) return;
12	  throw new ForbiddenError('You do not have access to this order');
13	}
