55	export async function listOrders(req: Request, res: Response, next: NextFunction) {
56	  try {
57	    const pagination = parsePaginationParams(req.query);
58	    const role = req.user!.role;
59	    const filters: any = { status: req.query.status as string };
60	
61	    if (role === 'buyer') {
62	      // Buyers can only see their own orders
63	      filters.buyerId = req.user!.id;
64	    } else if (role === 'admin') {
65	      // Admins can optionally filter by buyer or dealership
66	      if (req.query.buyerId) filters.buyerId = req.query.buyerId as string;
67	      if (req.scope?.dealershipId) filters.dealershipId = req.scope.dealershipId;
68	      else if (req.query.dealershipId) filters.dealershipId = req.query.dealershipId as string;
69	    } else {
70	      // Staff/finance: scoped to their dealership
71	      filters.dealershipId = req.user!.dealershipId || req.scope?.dealershipId;
72	    }
73	    const result = await orderService.listOrders(filters, pagination);
74	    res.json(result);
75	  } catch (error) {
76	    next(error);
77	  }
78	}
