88	      userId: req.user!.id,
89	      role: req.user!.role,
90	      ip: req.ip || '',
91	      action: `order.transition.${event}`,
92	      resourceType: 'order',
93	      resourceId: req.params.id,
94	      before: { status: beforeOrder.status },
95	      after: { status: (order as any).status, reason },
96	      requestId: (req as any).requestId,
97	    });
98	    res.json(order);
99	  } catch (error) {
100	    next(error);
101	  }
102	}
