115	export async function mergeOrders(req: Request, res: Response, next: NextFunction) {
116	  try {
117	    const { orderIds } = req.body;
118	    // Validate access to all orders before merging
119	    for (const oid of orderIds) {
120	      const order = await orderService.getOrder(oid);
121	      assertOrderAccess(order, req);
122	    }
123	    const merged = await orderService.mergeOrders(orderIds, req.user!.id);
124	    await logAuditEvent({
125	      dealershipId: (merged as any).dealershipId?.toString(),
126	      userId: req.user!.id,
127	      role: req.user!.role,
128	      ip: req.ip || '',
129	      action: 'order.merge',
130	      resourceType: 'order',
131	      resourceId: (merged as any)._id?.toString() || '',
132	      after: { mergedFrom: orderIds, orderNumber: (merged as any).orderNumber },
133	      requestId: (req as any).requestId,
134	    });
135	    res.json(merged);
136	  } catch (error) {
137	    next(error);
138	  }
139	}
