135	interface SagaStep {
136	  name: string;
137	  execute: () => Promise<void>;
138	  compensate: () => Promise<void>;
139	}
140	
141	async function executeSaga(steps: SagaStep[], orderId: string) {
142	  const completed: SagaStep[] = [];
143	  for (const step of steps) {
144	    try {
145	      await step.execute();
146	      completed.push(step);
147	    } catch (error: any) {
148	      logger.error({ orderId, failedStep: step.name, error: error.message }, 'Saga step failed, compensating');
149	      // Compensate in reverse order
150	      for (let i = completed.length - 1; i >= 0; i--) {
151	        try {
152	          await completed[i].compensate();
153	          logger.info({ orderId, step: completed[i].name }, 'Compensation step succeeded');
154	        } catch (compErr: any) {
155	          logger.error({ orderId, step: completed[i].name, error: compErr.message }, 'Compensation step failed');
156	        }
157	      }
158	      throw error;
159	    }
160	  }
161	}
