22	export async function checkPermission(
23	  userId: string,
24	  role: string,
25	  dealershipId: string,
26	  resource: string,
27	  resourceId: string | null,
28	  action: string,
29	  sensitiveFlag: boolean = false
30	): Promise<boolean> {
31	  if (role === Role.ADMIN) return true;
32	
33	  if (sensitiveFlag && role !== Role.FINANCE_REVIEWER && role !== Role.ADMIN) {
34	    const override = await PermissionOverride.findOne({
35	      dealershipId,
36	      resource,
37	      resourceId,
38	      userId,
39	      actions: action,
40	      effect: PermissionEffect.ALLOW,
41	      $or: [{ expiresAt: null }, { expiresAt: { $gt: new Date() } }],
42	    });
43	    if (override) return true;
44	
45	    // Also check document-level overrides for document resources
46	    if (resource === 'document' && resourceId) {
47	      const hasDocOverride = await checkDocumentLevelOverride(resourceId, userId, action);
48	      if (hasDocOverride) return true;
49	    }
50	
51	    return false;
52	  }
53	
54	  // Check PermissionOverride model (admin-managed overrides)
55	  if (resourceId) {
56	    const userOverride = await PermissionOverride.findOne({
57	      dealershipId,
58	      resource,
59	      resourceId,
60	      userId,
61	      actions: action,
62	      $or: [{ expiresAt: null }, { expiresAt: { $gt: new Date() } }],
63	    });
64	    if (userOverride) return userOverride.effect === PermissionEffect.ALLOW;
65	
66	    const roleOverride = await PermissionOverride.findOne({
67	      dealershipId,
68	      resource,
69	      resourceId,
70	      role,
71	      userId: null,
72	      actions: action,
73	      $or: [{ expiresAt: null }, { expiresAt: { $gt: new Date() } }],
74	    });
75	    if (roleOverride) return roleOverride.effect === PermissionEffect.ALLOW;
76	  }
77	
78	  // Check document-level overrides (from share workflow)
79	  if (resource === 'document' && resourceId) {
80	    const hasDocOverride = await checkDocumentLevelOverride(resourceId, userId, action);
81	    if (hasDocOverride) return true;
82	  }
83	
84	  const userDealershipOverride = await PermissionOverride.findOne({
85	    dealershipId,
86	    resource,
87	    resourceId: null,
88	    userId,
89	    actions: action,
90	    $or: [{ expiresAt: null }, { expiresAt: { $gt: new Date() } }],
91	  });
92	  if (userDealershipOverride) return userDealershipOverride.effect === PermissionEffect.ALLOW;
93	
94	  const roleDealershipOverride = await PermissionOverride.findOne({
95	    dealershipId,
96	    resource,
97	    resourceId: null,
98	    role,
99	    userId: null,
100	    actions: action,
101	    $or: [{ expiresAt: null }, { expiresAt: { $gt: new Date() } }],
102	  });
103	  if (roleDealershipOverride) return roleDealershipOverride.effect === PermissionEffect.ALLOW;
104	
105	  const resourceDefaults = DEFAULT_PERMISSIONS[resource];
106	  if (!resourceDefaults) return false;
107	  const roleDefaults = resourceDefaults[role];
108	  if (!roleDefaults) return false;
109	  return roleDefaults.includes(action);
110	}
