12	function assertFinanceAccess(order: any, req: Request) {
13	  if (req.user!.role === 'admin') return;
14	  if (req.user!.role === 'finance_reviewer') {
15	    const userDealership = req.user!.dealershipId || req.scope?.dealershipId;
16	    if (userDealership && order.dealershipId?.toString() === userDealership) return;
17	  }
18	  const userDealership = req.user!.dealershipId || req.scope?.dealershipId;
19	  if (userDealership && order.dealershipId?.toString() === userDealership) {
20	    if (order.buyerId?.toString() === req.user!.id || (order.buyerId as any)?._id?.toString() === req.user!.id) return;
21	    if (req.user!.role === 'dealership_staff') return;
22	  }
23	  throw new ForbiddenError('You do not have access to this financial record');
24	}
