103	function resolveAccountId(req: Request): string {
104	  const role = req.user!.role;
105	  // Admins can query specific accounts via X-Dealership-Id header scope
106	  if (role === 'admin' && req.scope?.dealershipId) {
107	    return `dealership:${req.scope.dealershipId}`;
108	  }
109	  if (role === 'buyer') return `buyer:${req.user!.id}`;
110	  const dealershipId = req.user!.dealershipId || req.scope?.dealershipId;
111	  if (dealershipId && (role === 'dealership_staff' || role === 'finance_reviewer')) {
112	    return `dealership:${dealershipId}`;
113	  }
114	  return `user:${req.user!.id}`;
115	}
