17	// Uses the same permission resolution logic as production permission.service.ts checkPermission()
18	// This is a synchronous version for unit testing without MongoDB
19	function checkPermission(userId, role, resource, resourceId, action, sensitiveFlag, overrides) {
20	  // Line 29 of permission.service.ts: admin always has access
21	  if (role === Role.ADMIN) return true;
22	
23	  // Lines 31-50: Sensitive flag handling
24	  if (sensitiveFlag && role !== Role.FINANCE_REVIEWER && role !== Role.ADMIN) {
25	    const override = overrides.find(
26	      (o) => o.effect === PermissionEffect.ALLOW && o.actions.includes(action) && (o.userId === userId || o.userId === null)
27	    );
28	    return !!override;
29	  }
30	
31	  // Lines 53-73: Check user-specific and role overrides
32	  const userOverride = overrides.find(
33	    (o) => o.userId === userId && o.resourceId === resourceId && o.actions.includes(action)
34	  );
35	  if (userOverride) return userOverride.effect === PermissionEffect.ALLOW;
36	
37	  const roleOverride = overrides.find(
38	    (o) => o.role === role && o.userId === null && o.resourceId === resourceId && o.actions.includes(action)
39	  );
40	  if (roleOverride) return roleOverride.effect === PermissionEffect.ALLOW;
41	
42	  // Lines 103-107: Fall back to DEFAULT_PERMISSIONS
43	  const resourceDefaults = DEFAULT_PERMISSIONS[resource];
44	  if (!resourceDefaults) return false;
45	  const roleDefaults = resourceDefaults[role];
46	  if (!roleDefaults) return false;
47	  return roleDefaults.includes(action);
48	}
