27	function shouldPurgeUser(user) {
28	  if (!user.pendingPurge || !user.deletedAt) return false;
29	  const thirtyDaysAgo = new Date(Date.now() - USER_PURGE_DAYS * 24 * 60 * 60 * 1000);
30	  return user.deletedAt <= thirtyDaysAgo;
