41	export function generateHmac(
42	  method: string,
43	  path: string,
44	  body: string,
45	  timestamp: string,
46	  secret: string
47	): string {
48	  const payload = `${method}\n${path}\n${body}\n${timestamp}`;
49	  return crypto.createHmac('sha256', secret).update(payload).digest('hex');
50	}
51	
52	export function verifyHmac(
53	  signature: string,
54	  method: string,
55	  path: string,
56	  body: string,
57	  timestamp: string,
58	  secret: string
59	): boolean {
60	  const expected = generateHmac(method, path, body, timestamp, secret);
61	  return crypto.timingSafeEqual(
62	    Buffer.from(signature, 'hex'),
63	    Buffer.from(expected, 'hex')
64	  );
65	}
66	
67	export function hashFile(buffer: Buffer): string {
68	  return crypto.createHash('sha256').update(buffer).digest('hex');
69	}
70	
71	export function generateKeyPair(): { key: Buffer; keyId: string } {
72	  return {
73	    key: crypto.randomBytes(32),
74	    keyId: crypto.randomUUID(),
75	  };
76	}
