24	export async function addToCart(
25	  userId: string,
26	  dealershipId: string,
27	  vehicleId: string,
28	  addOnServices: Array<{ serviceCode: string }> = []
29	) {
30	  const vehicle = await Vehicle.findById(vehicleId);
31	  if (!vehicle) throw new NotFoundError('Vehicle not found');
32	  if (vehicle.status !== VehicleStatus.AVAILABLE) {
33	    throw new BadRequestError('Vehicle is not available');
34	  }
35	
36	  let cart = await Cart.findOne({ userId, dealershipId });
37	  if (!cart) {
38	    cart = new Cart({ userId, dealershipId, items: [] });
