40	
41	  const alreadyInCart = cart.items.some(
42	    (item) => item.vehicleId.toString() === vehicleId
43	  );
44	  if (alreadyInCart) {
45	    throw new BadRequestError('Vehicle already in cart');
46	  }
47	
48	  const addOns = addOnServices
49	    .map((a) => AVAILABLE_ADDONS.find((ao) => ao.serviceCode === a.serviceCode))
50	    .filter(Boolean) as typeof AVAILABLE_ADDONS;
51	
52	  cart.items.push({
53	    vehicleId: vehicle._id as any,
54	    addOnServices: addOns,
55	    addedAt: new Date(),
56	  });
57	
