44	httpClient.interceptors.request.use(async (config) => {
45	  const token = localStorage.getItem('accessToken');
46	  if (token) {
47	    config.headers.Authorization = `Bearer ${token}`;
48	  }
49	
50	  const timestamp = new Date().toISOString();
51	  config.headers['X-Timestamp'] = timestamp;
52	
53	  const fullUrl = config.baseURL
54	    ? `${config.baseURL}${config.url || ''}`
55	    : config.url || '';
56	
57	  if (needsHmac(fullUrl)) {
58	    const method = (config.method || 'GET').toUpperCase();
59	    // Build the path as the server sees it (includes query string)
60	    let path = fullUrl;
61	    if (config.params) {
62	      const qs = new URLSearchParams(config.params).toString();
63	      if (qs) path = `${path}?${qs}`;
64	    }
65	    const body = config.data ? (typeof config.data === 'string' ? config.data : JSON.stringify(config.data)) : '';
66	    config.headers['X-Hmac-Signature'] = await generateHmac(method, path, body, timestamp, HMAC_SECRET);
67	  }
68	
69	  return config;
70	});
71	
72	httpClient.interceptors.response.use(
73	  (response) => response,
74	  async (error) => {
75	    if (error.response?.status === 401) {
76	      const refreshToken = localStorage.getItem('refreshToken');
77	      if (refreshToken && !error.config._retry) {
78	        error.config._retry = true;
79	        try {
80	          const { data } = await axios.post(`${API_BASE}/auth/refresh`, { refreshToken });
81	          localStorage.setItem('accessToken', data.accessToken);
82	          localStorage.setItem('refreshToken', data.refreshToken);
83	          error.config.headers.Authorization = `Bearer ${data.accessToken}`;
84	          return httpClient(error.config);
85	        } catch {
86	          localStorage.removeItem('accessToken');
87	          localStorage.removeItem('refreshToken');
88	          window.location.href = '/login';
89	        }
90	      }
91	    }
92	    return Promise.reject(error);
93	  }
94	);
