40	function request(method, path, body, token, opts) {
41	  return new Promise((resolve, reject) => {
42	    const url = new URL(path, BASE_URL);
43	    const fullPath = url.pathname + url.search;
44	    const timestamp = (opts && opts.timestamp) || new Date().toISOString();
45	    const bodyStr = body ? JSON.stringify(body) : '';
46	
47	    const options = {
48	      hostname: url.hostname,
49	      port: url.port,
50	      path: fullPath,
51	      method,
52	      headers: {
53	        'Content-Type': 'application/json',
54	        'X-Timestamp': timestamp,
55	      },
56	    };
57	
58	    if (!(opts && opts.skipHmac)) {
59	      const signature = generateHmac(method, fullPath, bodyStr, timestamp, HMAC_SECRET);
60	      options.headers['X-Hmac-Signature'] = signature;
61	    }
62	
63	    if (opts && opts.headers) {
64	      Object.assign(options.headers, opts.headers);
65	    }
66	
67	    if (token) options.headers['Authorization'] = `Bearer ${token}`;
68	
69	    const req = http.request(options, (res) => {
70	      let data = '';
71	      res.on('data', (chunk) => { data += chunk; });
72	      res.on('end', () => {
73	        let parsed;
74	        try { parsed = JSON.parse(data); } catch { parsed = data; }
75	        resolve({ status: res.statusCode, data: parsed });
76	      });
77	    });
78	
79	    req.on('error', reject);
80	    if (body) req.write(JSON.stringify(body));
81	    req.end();
82	  });
83	}
