365	function waitForServer(retries = 30, delay = 2000) {
366	  return new Promise((resolve, reject) => {
367	    function attempt(n) {
368	      request('GET', '/api/v1/health')
369	        .then((res) => {
370	          if (res.status === 200) resolve();
371	          else if (n <= 0) reject(new Error('Server not ready'));
372	          else setTimeout(() => attempt(n - 1), delay);
373	        })
374	        .catch(() => {
375	          if (n <= 0) reject(new Error('Server not reachable'));
376	          else setTimeout(() => attempt(n - 1), delay);
377	        });
378	    }
379	    attempt(retries);
380	  });
381	}
