1	import { Request, Response, NextFunction } from 'express';
2	import { verifyHmac } from '../lib/crypto';
3	import { UnauthorizedError } from '../lib/errors';
4	import { getRedisClient } from '../config/redis';
5	import config from '../config';
6	
7	export async function hmacVerify(
8	  req: Request,
9	  _res: Response,
10	  next: NextFunction
11	): Promise<void> {
12	  try {
13	    const signature = req.headers['x-hmac-signature'] as string;
14	    const timestamp = req.headers['x-timestamp'] as string;
15	
16	    if (!signature || !timestamp) {
17	      throw new UnauthorizedError('Missing HMAC signature or timestamp');
18	    }
19	
20	    // Guard: signature must be valid hex and correct length for SHA-256 (64 hex chars)
21	    if (!/^[0-9a-fA-F]{64}$/.test(signature)) {
22	      throw new UnauthorizedError('Invalid HMAC signature format');
23	    }
24	
25	    // Guard: timestamp must be a parseable date
26	    const requestTime = new Date(timestamp).getTime();
27	    if (isNaN(requestTime)) {
28	      throw new UnauthorizedError('Invalid timestamp format');
29	    }
30	
31	    const now = Date.now();
32	    const drift = Math.abs(now - requestTime) / 1000;
33	
34	    if (drift > config.hmacWindowSeconds) {
35	      throw new UnauthorizedError('Request timestamp outside acceptable window');
36	    }
37	
38	    // For multipart/form-data (file uploads), body is not JSON-serializable at this point
39	    // so we sign with empty body — the client must do the same for multipart requests
40	    const contentType = req.headers['content-type'] || '';
41	    const isMultipart = contentType.includes('multipart/form-data');
42	    const rawBody = isMultipart ? '' : (req.body && Object.keys(req.body).length > 0 ? JSON.stringify(req.body) : '');
43	
44	    const valid = verifyHmac(
45	      signature,
46	      req.method,
47	      req.originalUrl,
48	      rawBody,
49	      timestamp,
50	      config.hmacSecret
51	    );
52	
53	    if (!valid) {
54	      throw new UnauthorizedError('Invalid HMAC signature');
55	    }
56	
57	    const redis = getRedisClient();
58	    const nonceKey = `hmac:nonce:${signature}`;
59	    const exists = await redis.exists(nonceKey);
60	
61	    if (exists) {
62	      throw new UnauthorizedError('Replay detected: request already processed');
63	    }
64	
65	    await redis.setex(nonceKey, config.hmacWindowSeconds + 10, '1');
66	
67	    next();
68	  } catch (error) {
69	    // Ensure any unexpected crypto errors surface as 401, not 500
70	    if (error instanceof UnauthorizedError) {
71	      next(error);
72	    } else {
73	      next(new UnauthorizedError('HMAC verification failed'));
74	    }
75	  }
76	}
